using BackEndAluguel.Application.Auth.DTOs;
using MediatR;

namespace BackEndAluguel.Application.Auth.Comandos;

/// <summary>
/// Comando CQRS para autenticacao do administrador (host/locador).
/// Valida e-mail e senha contra o banco de dados.
/// </summary>
/// <param name="Email">E-mail cadastrado do host.</param>
/// <param name="Senha">Senha em texto plano (verificada via hash PBKDF2).</param>
public record LoginHostComando(
    string Email,
    string Senha
) : IRequest<TokenResultadoDto>;

/// <summary>
/// Comando CQRS para registro de um novo host/locador na plataforma.
/// Cria a conta com e-mail pendente de confirmação e envia o link por e-mail.
/// </summary>
/// <param name="NomeCompleto">Nome completo do host.</param>
/// <param name="Cpf">CPF do host (com ou sem formatação).</param>
/// <param name="DataNascimento">Data de nascimento do host.</param>
/// <param name="Email">E-mail do host (utilizado como login).</param>
/// <param name="Senha">Senha em texto plano (será criptografada antes de armazenar).</param>
public record RegistrarHostComando(
    string NomeCompleto,
    string Cpf,
    DateOnly DataNascimento,
    string Email,
    string Senha
) : IRequest<HostDto>;

/// <summary>
/// Comando CQRS para confirmação de e-mail do host.
/// Recebe o token enviado por e-mail e ativa a conta.
/// </summary>
/// <param name="Token">Token único recebido no e-mail de confirmação.</param>
public record ConfirmarEmailHostComando(
    string Token
) : IRequest<bool>;

/// <summary>
/// Comando CQRS para autenticacao de um inquilino.
/// Utiliza CPF + data de nascimento como credenciais (segundo fator de identidade).
/// </summary>
/// <param name="Cpf">CPF do inquilino (com ou sem formatacao).</param>
/// <param name="DataNascimento">Data de nascimento do inquilino.</param>
public record LoginInquilinoComando(
    string Cpf,
    DateOnly DataNascimento
) : IRequest<TokenResultadoDto>;

namespace BackEndAluguel.Application.Auth.DTOs;

/// <summary>
/// DTO de retorno com os dados do host após registro ou consulta de perfil.
/// </summary>
/// <param name="Id">Identificador único do host.</param>
/// <param name="NomeCompleto">Nome completo do host.</param>
/// <param name="Cpf">CPF do host (somente dígitos).</param>
/// <param name="DataNascimento">Data de nascimento do host.</param>
/// <param name="Email">E-mail do host.</param>
/// <param name="EmailConfirmado">Indica se o e-mail foi confirmado.</param>
/// <param name="CriadoEm">Data de criação da conta.</param>
public record HostDto(
    Guid Id,
    string NomeCompleto,
    string Cpf,
    DateOnly DataNascimento,
    string Email,
    bool EmailConfirmado,
    DateTime CriadoEm
);

namespace BackEndAluguel.Application.Auth.DTOs;

/// <summary>
/// DTO de resposta para operacoes de autenticacao bem-sucedidas.
/// Contem o token JWT e informacoes do usuario autenticado.
/// </summary>
/// <param name="Token">Token JWT assinado para uso nas requisicoes subsequentes.</param>
/// <param name="Perfil">Perfil do usuario autenticado: "Host" ou "Inquilino".</param>
/// <param name="NomeCompleto">Nome completo do usuario autenticado.</param>
/// <param name="InquilinoId">Identificador do inquilino (nulo para o host).</param>
/// <param name="HostId">Identificador do host (nulo para inquilinos).</param>
/// <param name="Expiracao">Data e hora de expiracao do token (UTC).</param>
public record TokenResultadoDto(
    string Token,
    string Perfil,
    string NomeCompleto,
    Guid? InquilinoId,
    Guid? HostId,
    DateTime Expiracao
);

namespace BackEndAluguel.Application.Auth;

/// <summary>
/// Contrato para envio de e-mails transacionais.
/// A implementação concreta fica na camada Infrastructure (SMTP via System.Net.Mail).
/// </summary>
public interface IEmailServico
{
    /// <summary>
    /// Envia o e-mail de confirmação de conta para o host recém-registrado.
    /// </summary>
    /// <param name="destinatario">Endereço de e-mail do destinatário.</param>
    /// <param name="nomeDestinatario">Nome do destinatário para personalização.</param>
    /// <param name="tokenConfirmacao">Token único de confirmação de conta.</param>
    /// <param name="cancellationToken">Token de cancelamento.</param>
    Task EnviarConfirmacaoContaAsync(
        string destinatario,
        string nomeDestinatario,
        string tokenConfirmacao,
        CancellationToken cancellationToken = default);
}

namespace BackEndAluguel.Application.Auth;

/// <summary>
/// Contrato para geracao de tokens JWT para autenticacao de host e inquilinos.
/// A implementacao concreta fica na camada Infrastructure.
/// Retorna o token e a data de expiracao para evitar dependencia de IConfiguration na camada Application.
/// </summary>
public interface IJwtServico
{
    /// <summary>
    /// Gera um token JWT para o administrador (host/locador) autenticado pelo banco de dados.
    /// </summary>
    /// <param name="hostId">Identificador único do host.</param>
    /// <param name="nomeCompleto">Nome completo do host.</param>
    /// <param name="email">E-mail do host.</param>
    /// <returns>Token JWT assinado e data/hora de expiracao (UTC).</returns>
    (string Token, DateTime Expiracao) GerarTokenHost(Guid hostId, string nomeCompleto, string email);

    /// <summary>
    /// Gera um token JWT para um inquilino autenticado.
    /// O token contera o InquilinoId, nome e CPF como claims.
    /// </summary>
    /// <param name="inquilinoId">Identificador unico do inquilino.</param>
    /// <param name="nomeCompleto">Nome completo do inquilino.</param>
    /// <param name="cpf">CPF do inquilino.</param>
    /// <returns>Token JWT assinado e data/hora de expiracao (UTC).</returns>
    (string Token, DateTime Expiracao) GerarTokenInquilino(Guid inquilinoId, string nomeCompleto, string cpf);
}

namespace BackEndAluguel.Application.Auth;

/// <summary>
/// Contrato para hashing e verificação de senhas.
/// A implementação concreta fica na camada Infrastructure (PBKDF2-SHA256).
/// </summary>
public interface ISenhaServico
{
    /// <summary>
    /// Gera um hash seguro da senha em texto plano.
    /// </summary>
    /// <param name="senhaPlana">Senha em texto plano fornecida pelo usuário.</param>
    /// <returns>Hash da senha (base64, inclui salt).</returns>
    string HashearSenha(string senhaPlana);

    /// <summary>
    /// Verifica se a senha em texto plano corresponde ao hash armazenado.
    /// </summary>
    /// <param name="senhaPlana">Senha em texto plano a verificar.</param>
    /// <param name="hashArmazenado">Hash armazenado no banco de dados.</param>
    /// <returns>True se a senha for correta.</returns>
    bool VerificarSenha(string senhaPlana, string hashArmazenado);
}

using BackEndAluguel.Application.Auth.Comandos;
using BackEndAluguel.Application.Auth.DTOs;
using BackEndAluguel.Application.Comum.Excecoes;
using BackEndAluguel.Domain.Entidades;
using BackEndAluguel.Domain.Interfaces;
using MediatR;

namespace BackEndAluguel.Application.Auth.Manipuladores;

/// <summary>
/// Manipulador CQRS para autenticacao do administrador (host/locador).
/// Valida e-mail e senha contra o banco de dados e retorna um token JWT.
/// </summary>
public class LoginHostManipulador : IRequestHandler<LoginHostComando, TokenResultadoDto>
{
    private readonly IHostRepositorio _hostRepositorio;
    private readonly ISenhaServico _senhaServico;
    private readonly IJwtServico _jwtServico;

    public LoginHostManipulador(
        IHostRepositorio hostRepositorio,
        ISenhaServico senhaServico,
        IJwtServico jwtServico)
    {
        _hostRepositorio = hostRepositorio;
        _senhaServico = senhaServico;
        _jwtServico = jwtServico;
    }

    /// <summary>
    /// Autentica o host pelo e-mail e senha.
    /// Retorna token JWT apenas se o e-mail estiver confirmado.
    /// </summary>
    public async Task<TokenResultadoDto> Handle(LoginHostComando request, CancellationToken cancellationToken)
    {
        var emailLimpo = request.Email.Trim().ToLowerInvariant();
        var host = await _hostRepositorio.ObterPorEmailAsync(emailLimpo, cancellationToken);

        if (host is null || !_senhaServico.VerificarSenha(request.Senha, host.SenhaHash))
            throw new RegraDeNegocioExcecao("E-mail ou senha inválidos.");

        if (!host.EmailConfirmado)
            throw new RegraDeNegocioExcecao("Conta não confirmada. Verifique seu e-mail e clique no link de confirmação.");

        var (token, expiracao) = _jwtServico.GerarTokenHost(host.Id, host.NomeCompleto, host.Email);
        return new TokenResultadoDto(token, "Host", host.NomeCompleto, null, host.Id, expiracao);
    }
}

/// <summary>
/// Manipulador CQRS para registro de um novo host/locador.
/// Valida dados, cria a conta com senha criptografada, envia e-mail de confirmação.
/// </summary>
public class RegistrarHostManipulador : IRequestHandler<RegistrarHostComando, HostDto>
{
    private readonly IHostRepositorio _hostRepositorio;
    private readonly ISenhaServico _senhaServico;
    private readonly IEmailServico _emailServico;

    public RegistrarHostManipulador(
        IHostRepositorio hostRepositorio,
        ISenhaServico senhaServico,
        IEmailServico emailServico)
    {
        _hostRepositorio = hostRepositorio;
        _senhaServico = senhaServico;
        _emailServico = emailServico;
    }

    /// <summary>
    /// Registra um novo host: valida unicidade de CPF/e-mail, criptografa a senha,
    /// persiste no banco e envia o e-mail de confirmação.
    /// </summary>
    public async Task<HostDto> Handle(RegistrarHostComando request, CancellationToken cancellationToken)
    {
        // Validações de unicidade
        var emailLimpo = request.Email.Trim().ToLowerInvariant();
        var cpfLimpo = new string(request.Cpf.Where(char.IsDigit).ToArray());

        if (await _hostRepositorio.ExisteEmailAsync(emailLimpo, cancellationToken))
            throw new RegraDeNegocioExcecao("Já existe uma conta cadastrada com este e-mail.");

        if (await _hostRepositorio.ExisteCpfAsync(cpfLimpo, cancellationToken))
            throw new RegraDeNegocioExcecao("Já existe uma conta cadastrada com este CPF.");

        // Validação mínima de senha
        if (string.IsNullOrWhiteSpace(request.Senha) || request.Senha.Length < 6)
            throw new RegraDeNegocioExcecao("A senha deve ter no mínimo 6 caracteres.");

        // Cria o host com senha criptografada
        var senhaHash = _senhaServico.HashearSenha(request.Senha);
        var host = new Host(request.NomeCompleto, cpfLimpo, request.DataNascimento, emailLimpo, senhaHash);

        await _hostRepositorio.AdicionarAsync(host, cancellationToken);
        await _hostRepositorio.SalvarAlteracoesAsync(cancellationToken);

        // Envia e-mail de confirmação (não bloqueia o registro em caso de falha de envio)
        try
        {
            await _emailServico.EnviarConfirmacaoContaAsync(
                host.Email, host.NomeCompleto, host.TokenConfirmacao!, cancellationToken);
        }
        catch
        {
            // Falha no envio de e-mail não deve impedir o registro
            // O usuário pode solicitar reenvio futuramente
        }

        return ConverterParaDto(host);
    }

    private static HostDto ConverterParaDto(Host host) => new(
        host.Id,
        host.NomeCompleto,
        host.Cpf,
        host.DataNascimento,
        host.Email,
        host.EmailConfirmado,
        host.CriadoEm
    );
}

/// <summary>
/// Manipulador CQRS para confirmação de e-mail do host.
/// Valida o token e ativa a conta se for válido e não expirado.
/// </summary>
public class ConfirmarEmailHostManipulador : IRequestHandler<ConfirmarEmailHostComando, bool>
{
    private readonly IHostRepositorio _hostRepositorio;

    public ConfirmarEmailHostManipulador(IHostRepositorio hostRepositorio)
    {
        _hostRepositorio = hostRepositorio;
    }

    /// <summary>
    /// Valida o token de confirmação e ativa a conta do host.
    /// </summary>
    public async Task<bool> Handle(ConfirmarEmailHostComando request, CancellationToken cancellationToken)
    {
        var host = await _hostRepositorio.ObterPorTokenConfirmacaoAsync(request.Token, cancellationToken);

        if (host is null)
            throw new RegraDeNegocioExcecao("Token de confirmação inválido ou já utilizado.");

        if (!host.TokenConfirmacaoValido(request.Token))
            throw new RegraDeNegocioExcecao("Token de confirmação expirado. Solicite um novo e-mail de confirmação.");

        host.ConfirmarEmail();
        _hostRepositorio.Atualizar(host);
        await _hostRepositorio.SalvarAlteracoesAsync(cancellationToken);

        return true;
    }
}

/// <summary>
/// Manipulador CQRS para autenticacao de inquilinos via CPF + data de nascimento.
/// </summary>
public class LoginInquilinoManipulador : IRequestHandler<LoginInquilinoComando, TokenResultadoDto>
{
    private readonly IInquilinoRepositorio _inquilinoRepositorio;
    private readonly IJwtServico _jwtServico;

    /// <summary>Inicializa o manipulador com o repositorio de inquilinos e o servico JWT.</summary>
    public LoginInquilinoManipulador(IInquilinoRepositorio inquilinoRepositorio, IJwtServico jwtServico)
    {
        _inquilinoRepositorio = inquilinoRepositorio;
        _jwtServico = jwtServico;
    }

    /// <summary>
    /// Autentica o inquilino pelo CPF e data de nascimento.
    /// Retorna um token JWT com InquilinoId em caso de sucesso.
    /// </summary>
    public async Task<TokenResultadoDto> Handle(LoginInquilinoComando request, CancellationToken cancellationToken)
    {
        var cpfLimpo = new string(request.Cpf.Where(char.IsDigit).ToArray());

        var inquilino = await _inquilinoRepositorio.ObterPorCpfEDataNascimentoAsync(
            cpfLimpo, request.DataNascimento, cancellationToken);

        if (inquilino is null)
            throw new RegraDeNegocioExcecao("CPF ou data de nascimento incorretos.");

        var (token, expiracao) = _jwtServico.GerarTokenInquilino(inquilino.Id, inquilino.NomeCompleto, inquilino.Cpf);
        return new TokenResultadoDto(token, "Inquilino", inquilino.NomeCompleto, inquilino.Id, null, expiracao);
    }
}

using BackEndAluguel.Application.Comum.Excecoes;
using BackEndAluguel.Application.Configuracoes.Comandos;
using BackEndAluguel.Application.Configuracoes.Consultas;
using BackEndAluguel.Application.Configuracoes.DTOs;
using BackEndAluguel.Application.Pagamentos;
using BackEndAluguel.Application.Pagamentos.DTOs;
using BackEndAluguel.Domain.Entidades;
using BackEndAluguel.Domain.Interfaces;
using MediatR;

namespace BackEndAluguel.Application.Configuracoes.Manipuladores;

/// <summary>
/// Manipulador CQRS para a consulta <see cref="ObterConfiguracaoConsulta"/>.
/// Retorna a configuracao global unica do sistema.
/// </summary>
public class ObterConfiguracaoManipulador : IRequestHandler<ObterConfiguracaoConsulta, ConfiguracaoDto?>
{
    private readonly IConfiguracaoRepositorio _repositorio;

    /// <summary>Inicializa o manipulador com o repositorio de configuracoes.</summary>
    public ObterConfiguracaoManipulador(IConfiguracaoRepositorio repositorio)
    {
        _repositorio = repositorio;
    }

    /// <summary>Processa a consulta retornando a configuracao atual.</summary>
    public async Task<ConfiguracaoDto?> Handle(ObterConfiguracaoConsulta request, CancellationToken cancellationToken)
    {
        var config = await _repositorio.ObterConfiguracaoAsync(cancellationToken);
        return config is null ? null : ConverterParaDto(config);
    }

    /// <summary>Converte a entidade Configuracao para DTO de resposta.</summary>
    internal static ConfiguracaoDto ConverterParaDto(Configuracao c)
        => new(c.Id, c.KwhValor, c.ValorAgua, c.AtualizadoEm, c.WalletIdAsaas);
}

/// <summary>
/// Manipulador CQRS para o comando <see cref="AtualizarConfiguracaoComando"/>.
/// Atualiza os valores globais de kWh e agua do sistema.
/// </summary>
public class AtualizarConfiguracaoManipulador : IRequestHandler<AtualizarConfiguracaoComando, ConfiguracaoDto>
{
    private readonly IConfiguracaoRepositorio _repositorio;

    /// <summary>Inicializa o manipulador com o repositorio de configuracoes.</summary>
    public AtualizarConfiguracaoManipulador(IConfiguracaoRepositorio repositorio)
    {
        _repositorio = repositorio;
    }

    /// <summary>Processa a atualizacao da configuracao global do sistema.</summary>
    public async Task<ConfiguracaoDto> Handle(AtualizarConfiguracaoComando request, CancellationToken cancellationToken)
    {
        var config = await _repositorio.ObterConfiguracaoAsync(cancellationToken)
            ?? throw new RegraDeNegocioExcecao("Configuracao global do sistema nao encontrada. Contate o suporte.");

        config.Atualizar(request.KwhValor, request.ValorAgua);
        _repositorio.Atualizar(config);
        await _repositorio.SalvarAlteracoesAsync(cancellationToken);

        return ObterConfiguracaoManipulador.ConverterParaDto(config);
    }
}

/// <summary>
/// Manipulador CQRS para o comando <see cref="CriarSubcontaAsaasComando"/>.
/// Registra o locador (host) na plataforma Asaas, obtendo o WalletId para uso no split de pagamentos PIX.
/// O WalletId e armazenado na Configuracao global para uso automatico na geracao de cobranças.
/// </summary>
public class CriarSubcontaAsaasManipulador : IRequestHandler<CriarSubcontaAsaasComando, SubcontaResultadoDto>
{
    private readonly IConfiguracaoRepositorio _configuracaoRepositorio;
    private readonly IServicoGatewayPagamento _gatewayPagamento;

    /// <summary>Inicializa o manipulador com os servicos necessarios.</summary>
    public CriarSubcontaAsaasManipulador(
        IConfiguracaoRepositorio configuracaoRepositorio,
        IServicoGatewayPagamento gatewayPagamento)
    {
        _configuracaoRepositorio = configuracaoRepositorio;
        _gatewayPagamento = gatewayPagamento;
    }

    /// <summary>
    /// Registra a subconta no Asaas e persiste o WalletId retornado na configuracao global.
    /// </summary>
    public async Task<SubcontaResultadoDto> Handle(CriarSubcontaAsaasComando request, CancellationToken cancellationToken)
    {
        var dados = new CriarSubcontaDto(
            Nome: request.Nome,
            Email: request.Email,
            CpfCnpj: request.CpfCnpj,
            TipoPessoa: request.TipoPessoa,
            Telefone: request.Telefone,
            Site: request.Site);

        var resultado = await _gatewayPagamento.CriarSubcontaAsync(dados, cancellationToken);

        // Persiste o WalletId na configuracao global para uso futuro no split PIX
        var config = await _configuracaoRepositorio.ObterConfiguracaoAsync(cancellationToken)
            ?? throw new RegraDeNegocioExcecao("Configuracao global nao encontrada. Contate o suporte.");

        config.AtualizarWalletIdAsaas(resultado.WalletId);
        _configuracaoRepositorio.Atualizar(config);
        await _configuracaoRepositorio.SalvarAlteracoesAsync(cancellationToken);

        return resultado;
    }
}

using BackEndAluguel.Application.Comum.Excecoes;
using BackEndAluguel.Application.Configuracoes.Comandos;
using BackEndAluguel.Application.Configuracoes.Consultas;
using BackEndAluguel.Application.Configuracoes.DTOs;
using BackEndAluguel.Application.Pagamentos;
using BackEndAluguel.Application.Pagamentos.DTOs;
using BackEndAluguel.Domain.Entidades;
using BackEndAluguel.Domain.Interfaces;
using MediatR;

namespace BackEndAluguel.Application.Configuracoes.Manipuladores;

/// <summary>
/// Manipulador CQRS para a consulta <see cref="ObterConfiguracaoConsulta"/>.
/// Retorna a configuracao global unica do sistema.
/// </summary>
public class ObterConfiguracaoManipulador : IRequestHandler<ObterConfiguracaoConsulta, ConfiguracaoDto?>
{
    private readonly IConfiguracaoRepositorio _repositorio;

    /// <summary>Inicializa o manipulador com o repositorio de configuracoes.</summary>
    public ObterConfiguracaoManipulador(IConfiguracaoRepositorio repositorio)
    {
        _repositorio = repositorio;
    }

    /// <summary>Processa a consulta retornando a configuracao atual.</summary>
    public async Task<ConfiguracaoDto?> Handle(ObterConfiguracaoConsulta request, CancellationToken cancellationToken)
    {
        var config = await _repositorio.ObterConfiguracaoAsync(cancellationToken);
        return config is null ? null : ConverterParaDto(config);
    }

    /// <summary>Converte a entidade Configuracao para DTO de resposta.</summary>
    internal static ConfiguracaoDto ConverterParaDto(Configuracao c)
        => new(c.Id, c.KwhValor, c.ValorAgua, c.AtualizadoEm, c.WalletIdAsaas);
}

/// <summary>
/// Manipulador CQRS para o comando <see cref="AtualizarConfiguracaoComando"/>.
/// Atualiza os valores globais de kWh e agua do sistema.
/// </summary>
public class AtualizarConfiguracaoManipulador : IRequestHandler<AtualizarConfiguracaoComando, ConfiguracaoDto>
{
    private readonly IConfiguracaoRepositorio _repositorio;

    /// <summary>Inicializa o manipulador com o repositorio de configuracoes.</summary>
    public AtualizarConfiguracaoManipulador(IConfiguracaoRepositorio repositorio)
    {
        _repositorio = repositorio;
    }

    /// <summary>Processa a atualizacao da configuracao global do sistema (cria se nao existir — upsert).</summary>
    public async Task<ConfiguracaoDto> Handle(AtualizarConfiguracaoComando request, CancellationToken cancellationToken)
    {
        var config = await _repositorio.ObterConfiguracaoAsync(cancellationToken);

        if (config is null)
        {
            // Primeira configuracao: cria o registro singleton
            config = new Configuracao(request.KwhValor, request.ValorAgua);
            await _repositorio.AdicionarAsync(config, cancellationToken);
        }
        else
        {
            config.Atualizar(request.KwhValor, request.ValorAgua);
            _repositorio.Atualizar(config);
        }

        await _repositorio.SalvarAlteracoesAsync(cancellationToken);
        return ObterConfiguracaoManipulador.ConverterParaDto(config);
    }
}

/// <summary>
/// Manipulador CQRS para o comando <see cref="CriarSubcontaAsaasComando"/>.
/// Registra o locador (host) na plataforma Asaas, obtendo o WalletId para uso no split de pagamentos PIX.
/// O WalletId e armazenado na Configuracao global para uso automatico na geracao de cobranças.
/// </summary>
public class CriarSubcontaAsaasManipulador : IRequestHandler<CriarSubcontaAsaasComando, SubcontaResultadoDto>
{
    private readonly IConfiguracaoRepositorio _configuracaoRepositorio;
    private readonly IServicoGatewayPagamento _gatewayPagamento;

    /// <summary>Inicializa o manipulador com os servicos necessarios.</summary>
    public CriarSubcontaAsaasManipulador(
        IConfiguracaoRepositorio configuracaoRepositorio,
        IServicoGatewayPagamento gatewayPagamento)
    {
        _configuracaoRepositorio = configuracaoRepositorio;
        _gatewayPagamento = gatewayPagamento;
    }

    /// <summary>
    /// Registra a subconta no Asaas e persiste o WalletId retornado na configuracao global.
    /// </summary>
    public async Task<SubcontaResultadoDto> Handle(CriarSubcontaAsaasComando request, CancellationToken cancellationToken)
    {
        var dados = new CriarSubcontaDto(
            Nome: request.Nome,
            Email: request.Email,
            CpfCnpj: request.CpfCnpj,
            TipoPessoa: request.TipoPessoa,
            Telefone: request.Telefone,
            Site: request.Site);

        var resultado = await _gatewayPagamento.CriarSubcontaAsync(dados, cancellationToken);

        // Persiste o WalletId na configuracao global para uso futuro no split PIX
        var config = await _configuracaoRepositorio.ObterConfiguracaoAsync(cancellationToken)
            ?? throw new RegraDeNegocioExcecao("Configuracao global nao encontrada. Contate o suporte.");

        config.AtualizarWalletIdAsaas(resultado.WalletId);
        _configuracaoRepositorio.Atualizar(config);
        await _configuracaoRepositorio.SalvarAlteracoesAsync(cancellationToken);

        return resultado;
    }
}

