namespace BackEndAluguel.Domain.Entidades;

/// <summary>
/// Representa um administrador (locador/host) da plataforma GestAluguel.
/// Cada host é um usuário com acesso total ao painel de gerenciamento.
/// A conta deve ser confirmada por e-mail antes de ser utilizada.
/// </summary>
public class Host : EntidadeBase
{
    // ─── Propriedades ──────────────────────────────────────────────────────

    /// <summary>Nome completo do host.</summary>
    public string NomeCompleto { get; private set; } = string.Empty;

    /// <summary>CPF do host (somente dígitos, 11 caracteres).</summary>
    public string Cpf { get; private set; } = string.Empty;

    /// <summary>Data de nascimento do host.</summary>
    public DateOnly DataNascimento { get; private set; }

    /// <summary>Endereço de e-mail do host. Utilizado como login.</summary>
    public string Email { get; private set; } = string.Empty;

    /// <summary>Hash da senha do host gerado via PBKDF2-SHA256.</summary>
    public string SenhaHash { get; private set; } = string.Empty;

    /// <summary>Indica se o e-mail foi confirmado. A conta só pode ser usada após confirmação.</summary>
    public bool EmailConfirmado { get; private set; }

    /// <summary>Token único para confirmação de e-mail. Nulo após a confirmação.</summary>
    public string? TokenConfirmacao { get; private set; }

    /// <summary>Data de expiração do token de confirmação de e-mail.</summary>
    public DateTime? TokenExpiracaoConfirmacao { get; private set; }

    // ─── Construtor ────────────────────────────────────────────────────────

    /// <summary>
    /// Construtor protegido exigido pelo Entity Framework Core.
    /// Use o construtor público para criar instâncias desta entidade.
    /// </summary>
    protected Host() { }

    /// <summary>
    /// Cria um novo host com os dados fornecidos.
    /// A conta começa como não confirmada e recebe um token de confirmação de e-mail.
    /// </summary>
    /// <param name="nomeCompleto">Nome completo do host.</param>
    /// <param name="cpf">CPF (com ou sem formatação — será limpo automaticamente).</param>
    /// <param name="dataNascimento">Data de nascimento do host.</param>
    /// <param name="email">E-mail do host. Será armazenado em minúsculas.</param>
    /// <param name="senhaHash">Senha já criptografada via PBKDF2.</param>
    public Host(string nomeCompleto, string cpf, DateOnly dataNascimento, string email, string senhaHash)
    {
        ValidarNome(nomeCompleto);
        ValidarCpf(cpf);
        ValidarEmail(email);
        ValidarSenhaHash(senhaHash);

        NomeCompleto = nomeCompleto.Trim();
        Cpf = new string(cpf.Where(char.IsDigit).ToArray());
        DataNascimento = dataNascimento;
        Email = email.Trim().ToLowerInvariant();
        SenhaHash = senhaHash;
        EmailConfirmado = false;
        GerarTokenConfirmacao();
    }

    // ─── Métodos de domínio ────────────────────────────────────────────────

    /// <summary>
    /// Confirma o e-mail do host, limpando o token de confirmação.
    /// </summary>
    public void ConfirmarEmail()
    {
        EmailConfirmado = true;
        TokenConfirmacao = null;
        TokenExpiracaoConfirmacao = null;
        MarcarComoAtualizado();
    }

    /// <summary>
    /// Gera um novo token de confirmação de e-mail com expiração de 48 horas.
    /// Útil para reenvio de e-mail de confirmação.
    /// </summary>
    public void GerarTokenConfirmacao()
    {
        TokenConfirmacao = Guid.NewGuid().ToString("N") + Guid.NewGuid().ToString("N");
        TokenExpiracaoConfirmacao = DateTime.UtcNow.AddHours(48);
        MarcarComoAtualizado();
    }

    /// <summary>
    /// Verifica se o token de confirmação informado é válido e não expirou.
    /// </summary>
    public bool TokenConfirmacaoValido(string token)
        => TokenConfirmacao == token
           && TokenExpiracaoConfirmacao.HasValue
           && TokenExpiracaoConfirmacao.Value > DateTime.UtcNow;

    /// <summary>
    /// Atualiza os dados pessoais do host.
    /// </summary>
    public void Atualizar(string nomeCompleto, DateOnly dataNascimento)
    {
        ValidarNome(nomeCompleto);
        NomeCompleto = nomeCompleto.Trim();
        DataNascimento = dataNascimento;
        MarcarComoAtualizado();
    }

    /// <summary>
    /// Atualiza o hash da senha do host.
    /// </summary>
    public void AtualizarSenha(string novaSenhaHash)
    {
        ValidarSenhaHash(novaSenhaHash);
        SenhaHash = novaSenhaHash;
        MarcarComoAtualizado();
    }

    // ─── Validações privadas ───────────────────────────────────────────────

    private static void ValidarNome(string nome)
    {
        if (string.IsNullOrWhiteSpace(nome))
            throw new ArgumentException("O nome completo do host é obrigatório.", nameof(nome));
    }

    private static void ValidarCpf(string cpf)
    {
        var digitos = new string(cpf.Where(char.IsDigit).ToArray());
        if (digitos.Length != 11)
            throw new ArgumentException("O CPF deve conter exatamente 11 dígitos.", nameof(cpf));
    }

    private static void ValidarEmail(string email)
    {
        if (string.IsNullOrWhiteSpace(email) || !email.Contains('@'))
            throw new ArgumentException("O e-mail informado é inválido.", nameof(email));
    }

    private static void ValidarSenhaHash(string senhaHash)
    {
        if (string.IsNullOrWhiteSpace(senhaHash))
            throw new ArgumentException("O hash da senha não pode ser vazio.", nameof(senhaHash));
    }
}

namespace BackEndAluguel.Domain.Entidades;

/// <summary>
/// Entidade que representa um inquilino (locatário) de um apartamento.
/// Contém todos os dados pessoais, contratuais e de alertas de vencimento.
///
/// Relacionamentos:
/// - N Inquilinos para 1 Apartamento (chave estrangeira ApartamentoId).
/// - 1 Inquilino para N Faturas: cada inquilino pode ter múltiplas faturas mensais geradas.
/// </summary>
public class Inquilino : EntidadeBase
{
    /// <summary>
    /// Nome completo do inquilino.
    /// </summary>
    public string NomeCompleto { get; private set; } = string.Empty;

    /// <summary>
    /// CPF do inquilino, armazenado somente com dígitos (11 caracteres).
    /// </summary>
    public string Cpf { get; private set; } = string.Empty;

    /// <summary>
    /// Quantidade total de moradores que residirão no apartamento,
    /// incluindo o próprio inquilino.
    /// </summary>
    public int QuantidadeMoradores { get; private set; }

    /// <summary>
    /// Data em que o inquilino iniciou a ocupação do apartamento.
    /// </summary>
    public DateOnly DataEntrada { get; private set; }

    /// <summary>
    /// Data de vencimento do contrato de locação.
    /// </summary>
    public DateOnly DataVencimentoContrato { get; private set; }

    /// <summary>
    /// Valor fixo mensal do aluguel definido em contrato (em reais).
    /// </summary>
    public decimal ValorAluguel { get; private set; }

    /// <summary>
    /// Valor mensal cobrado pela vaga de garagem (0 se nao possui garagem).
    /// </summary>
    public decimal Garagem { get; private set; }

    /// <summary>
    /// Configuração dos alertas de vencimento de contrato em dias (ex: 30, 60, 90).
    /// Permite notificar o inquilino/administrador com antecedência sobre o fim do contrato.
    /// Armazenado como uma lista de inteiros representando os dias antes do vencimento.
    /// </summary>
    public List<int> DiasAlertaVencimento { get; private set; } = new();

    // =============================================================
    // RELACIONAMENTO: N Inquilinos -> 1 Apartamento
    // Vários inquilinos (histórico) podem estar vinculados a
    // um único apartamento. A chave estrangeira ApartamentoId
    // referencia a tabela Apartamentos.
    // =============================================================

    /// <summary>
    /// Identificador do apartamento ao qual este inquilino está vinculado.
    /// Chave estrangeira para a entidade Apartamento.
    /// </summary>
    public Guid ApartamentoId { get; private set; }

    /// <summary>
    /// Propriedade de navegação para o apartamento vinculado.
    /// Permite acessar os dados do apartamento diretamente através do inquilino.
    /// </summary>
    public Apartamento? Apartamento { get; private set; }

    // =============================================================
    // RELACIONAMENTO: 1 Inquilino -> N Faturas
    // Um inquilino pode ter uma fatura gerada por mês de referência.
    // O relacionamento é Um-para-Muitos (1:N).
    // =============================================================

    /// <summary>
    /// Coleção de faturas mensais geradas para este inquilino.
    /// Representa o relacionamento Um-para-Muitos (1:N) entre Inquilino e Fatura.
    /// </summary>
    public ICollection<Fatura> Faturas { get; private set; } = new List<Fatura>();

    /// <summary>
    /// Dependentes vinculados a este inquilino.
    /// </summary>
    public ICollection<Dependente> Dependentes { get; private set; } = new List<Dependente>();

    /// <summary>
    /// Construtor protegido requerido pelo Entity Framework Core.
    /// </summary>
    protected Inquilino() { }

    /// <summary>
    /// Cria um novo inquilino com todos os dados contratuais necessários.
    /// </summary>
    /// <param name="nomeCompleto">Nome completo do inquilino.</param>
    /// <param name="cpf">CPF do inquilino (apenas dígitos).</param>
    /// <param name="quantidadeMoradores">Número de moradores incluindo o inquilino.</param>
    /// <param name="dataEntrada">Data de início da ocupação.</param>
    /// <param name="dataVencimentoContrato">Data de encerramento do contrato.</param>
    /// <param name="valorAluguel">Valor mensal do aluguel em reais.</param>
    /// <param name="apartamentoId">Identificador do apartamento vinculado.</param>
    /// <param name="diasAlertaVencimento">Lista de dias de antecedência para alertas (ex: 30, 60, 90).</param>
    /// <param name="garagem">Valor mensal da vaga de garagem.</param>
    public Inquilino(
        string nomeCompleto,
        string cpf,
        int quantidadeMoradores,
        DateOnly dataEntrada,
        DateOnly dataVencimentoContrato,
        decimal valorAluguel,
        Guid apartamentoId,
        List<int>? diasAlertaVencimento = null,
        decimal garagem = 0m)
    {
        ValidarNome(nomeCompleto);
        ValidarCpf(cpf);
        ValidarQuantidadeMoradores(quantidadeMoradores);
        ValidarValorAluguel(valorAluguel);
        ValidarDatas(dataEntrada, dataVencimentoContrato);

        NomeCompleto = nomeCompleto.Trim();
        Cpf = LimparCpf(cpf);
        QuantidadeMoradores = quantidadeMoradores;
        DataEntrada = dataEntrada;
        DataVencimentoContrato = dataVencimentoContrato;
        ValorAluguel = valorAluguel;
        ApartamentoId = apartamentoId;
        DiasAlertaVencimento = diasAlertaVencimento ?? new List<int> { 30, 60, 90 };
        Garagem = garagem < 0 ? 0 : garagem;
    }

    /// <summary>
    /// Atualiza as informações do inquilino.
    /// </summary>
    /// <param name="nomeCompleto">Novo nome completo.</param>
    /// <param name="quantidadeMoradores">Nova quantidade de moradores.</param>
    /// <param name="dataVencimentoContrato">Nova data de vencimento do contrato.</param>
    /// <param name="valorAluguel">Novo valor mensal do aluguel.</param>
    /// <param name="diasAlertaVencimento">Nova lista de alertas de vencimento.</param>
    /// <param name="garagem">Novo valor mensal da vaga de garagem.</param>
    public void Atualizar(
        string nomeCompleto,
        int quantidadeMoradores,
        DateOnly dataVencimentoContrato,
        decimal valorAluguel,
        List<int>? diasAlertaVencimento = null,
        decimal garagem = 0m)
    {
        ValidarNome(nomeCompleto);
        ValidarQuantidadeMoradores(quantidadeMoradores);
        ValidarValorAluguel(valorAluguel);

        NomeCompleto = nomeCompleto.Trim();
        QuantidadeMoradores = quantidadeMoradores;
        DataVencimentoContrato = dataVencimentoContrato;
        ValorAluguel = valorAluguel;
        Garagem = garagem < 0 ? 0 : garagem;

        if (diasAlertaVencimento != null)
            DiasAlertaVencimento = diasAlertaVencimento;

        MarcarComoAtualizado();
    }

    /// <summary>
    /// Verifica se o contrato do inquilino vence dentro de um número específico de dias.
    /// Utilizado para disparar alertas de vencimento.
    /// </summary>
    /// <param name="diasAntecedencia">Quantidade de dias para verificar antecedência.</param>
    /// <returns>Verdadeiro se o contrato vence dentro dos dias especificados.</returns>
    public bool ContratoVenceEm(int diasAntecedencia)
    {
        var dataLimite = DateOnly.FromDateTime(DateTime.Today.AddDays(diasAntecedencia));
        return DataVencimentoContrato <= dataLimite && DataVencimentoContrato >= DateOnly.FromDateTime(DateTime.Today);
    }

    /// <summary>
    /// Verifica se algum alerta de vencimento está ativo com base na configuração de alertas.
    /// </summary>
    /// <returns>Lista de dias configurados onde o alerta está ativo no momento.</returns>
    public IEnumerable<int> ObterAlertasAtivos()
    {
        return DiasAlertaVencimento.Where(ContratoVenceEm);
    }

    /// <summary>
    /// Remove formatação do CPF, mantendo apenas os dígitos.
    /// </summary>
    private static string LimparCpf(string cpf)
        => new(cpf.Where(char.IsDigit).ToArray());

    /// <summary>
    /// Valida que o nome completo não está vazio.
    /// </summary>
    private static void ValidarNome(string nome)
    {
        if (string.IsNullOrWhiteSpace(nome))
            throw new ArgumentException("O nome completo do inquilino não pode ser vazio.", nameof(nome));
    }

    /// <summary>
    /// Valida o formato do CPF (deve conter 11 dígitos numéricos).
    /// </summary>
    private static void ValidarCpf(string cpf)
    {
        var digitos = new string(cpf.Where(char.IsDigit).ToArray());
        if (digitos.Length != 11)
            throw new ArgumentException("O CPF deve conter 11 dígitos numéricos.", nameof(cpf));
    }

    /// <summary>
    /// Valida que a quantidade de moradores é maior que zero.
    /// </summary>
    private static void ValidarQuantidadeMoradores(int quantidade)
    {
        if (quantidade <= 0)
            throw new ArgumentException("A quantidade de moradores deve ser maior que zero.", nameof(quantidade));
    }

    /// <summary>
    /// Valida que o valor do aluguel é maior que zero.
    /// </summary>
    private static void ValidarValorAluguel(decimal valor)
    {
        if (valor <= 0)
            throw new ArgumentException("O valor do aluguel deve ser maior que zero.", nameof(valor));
    }

    /// <summary>
    /// Valida que a data de entrada é anterior ou igual à data de vencimento do contrato.
    /// </summary>
    private static void ValidarDatas(DateOnly dataEntrada, DateOnly dataVencimento)
    {
        if (dataEntrada >= dataVencimento)
            throw new ArgumentException("A data de entrada deve ser anterior à data de vencimento do contrato.");
    }
}

using BackEndAluguel.Domain.Enumeradores;

namespace BackEndAluguel.Domain.Entidades;

/// <summary>
/// Entidade que representa um inquilino (locatário) de um apartamento.
/// O inquilino é também um morador e, portanto, compartilha os mesmos campos
/// pessoais obrigatórios que os dependentes (RG, órgão emissor, telefone, estado civil).
///
/// Relacionamentos:
/// - N Inquilinos para 1 Apartamento (chave estrangeira ApartamentoId).
/// - 1 Inquilino para N Faturas: cada inquilino pode ter múltiplas faturas mensais geradas.
/// </summary>
public class Inquilino : EntidadeBase
{
    /// <summary>Nome completo do inquilino.</summary>
    public string NomeCompleto { get; private set; } = string.Empty;

    /// <summary>CPF do inquilino, armazenado somente com dígitos (11 caracteres).</summary>
    public string Cpf { get; private set; } = string.Empty;

    /// <summary>RG do inquilino.</summary>
    public string Rg { get; private set; } = string.Empty;

    /// <summary>Órgão emissor do RG (ex: SSP-SP).</summary>
    public string OrgaoEmissor { get; private set; } = string.Empty;

    /// <summary>
    /// Data de nascimento do inquilino.
    /// Utilizada como segundo fator de autenticação no login do inquilino.
    /// </summary>
    public DateOnly DataNascimento { get; private set; }

    /// <summary>Telefone de contato do inquilino.</summary>
    public string Telefone { get; private set; } = string.Empty;

    /// <summary>Estado civil do inquilino.</summary>
    public EstadoCivil EstadoCivil { get; private set; }

    /// <summary>
    /// Quantidade total de moradores que residirão no apartamento,
    /// incluindo o próprio inquilino.
    /// </summary>
    public int QuantidadeMoradores { get; private set; }

    /// <summary>
    /// Data em que o inquilino iniciou a ocupação do apartamento.
    /// </summary>
    public DateOnly DataEntrada { get; private set; }

    /// <summary>
    /// Data de vencimento do contrato de locação.
    /// </summary>
    public DateOnly DataVencimentoContrato { get; private set; }

    /// <summary>
    /// Valor fixo mensal do aluguel definido em contrato (em reais).
    /// </summary>
    public decimal ValorAluguel { get; private set; }

    /// <summary>
    /// Valor mensal cobrado pela vaga de garagem (0 se nao possui garagem).
    /// </summary>
    public decimal Garagem { get; private set; }

    /// <summary>
    /// Configuração dos alertas de vencimento de contrato em dias (ex: 30, 60, 90).
    /// Permite notificar o inquilino/administrador com antecedência sobre o fim do contrato.
    /// Armazenado como uma lista de inteiros representando os dias antes do vencimento.
    /// </summary>
    public List<int> DiasAlertaVencimento { get; private set; } = new();

    // =============================================================
    // RELACIONAMENTO: N Inquilinos -> 1 Apartamento
    // Vários inquilinos (histórico) podem estar vinculados a
    // um único apartamento. A chave estrangeira ApartamentoId
    // referencia a tabela Apartamentos.
    // =============================================================

    /// <summary>
    /// Identificador do apartamento ao qual este inquilino está vinculado.
    /// Chave estrangeira para a entidade Apartamento.
    /// </summary>
    public Guid ApartamentoId { get; private set; }

    /// <summary>
    /// Propriedade de navegação para o apartamento vinculado.
    /// Permite acessar os dados do apartamento diretamente através do inquilino.
    /// </summary>
    public Apartamento? Apartamento { get; private set; }

    // =============================================================
    // RELACIONAMENTO: 1 Inquilino -> N Faturas
    // Um inquilino pode ter uma fatura gerada por mês de referência.
    // O relacionamento é Um-para-Muitos (1:N).
    // =============================================================

    /// <summary>
    /// Coleção de faturas mensais geradas para este inquilino.
    /// Representa o relacionamento Um-para-Muitos (1:N) entre Inquilino e Fatura.
    /// </summary>
    public ICollection<Fatura> Faturas { get; private set; } = new List<Fatura>();

    /// <summary>
    /// Dependentes vinculados a este inquilino.
    /// </summary>
    public ICollection<Dependente> Dependentes { get; private set; } = new List<Dependente>();

    /// <summary>
    /// Construtor protegido requerido pelo Entity Framework Core.
    /// </summary>
    protected Inquilino() { }

    /// <summary>
    /// Cria um novo inquilino com dados básicos (sem RG, órgão emissor, telefone e estado civil).
    /// Útil para cenários simplificados e testes.
    /// </summary>
    public Inquilino(
        string nomeCompleto,
        string cpf,
        int quantidadeMoradores,
        DateOnly dataEntrada,
        DateOnly dataVencimentoContrato,
        decimal valorAluguel,
        Guid apartamentoId,
        DateOnly dataNascimento = default,
        List<int>? diasAlertaVencimento = null,
        decimal garagem = 0m)
    {
        ValidarNome(nomeCompleto);
        ValidarCpf(cpf);
        ValidarQuantidadeMoradores(quantidadeMoradores);
        ValidarValorAluguel(valorAluguel);
        ValidarDatas(dataEntrada, dataVencimentoContrato);

        NomeCompleto = nomeCompleto.Trim();
        Cpf = LimparCpf(cpf);
        QuantidadeMoradores = quantidadeMoradores;
        DataEntrada = dataEntrada;
        DataVencimentoContrato = dataVencimentoContrato;
        ValorAluguel = valorAluguel;
        ApartamentoId = apartamentoId;
        DataNascimento = dataNascimento;
        DiasAlertaVencimento = diasAlertaVencimento ?? new List<int> { 30, 60, 90 };
        Garagem = garagem < 0 ? 0 : garagem;
    }

    /// <summary>
    /// Cria um novo inquilino com todos os dados pessoais e contratuais necessários.
    /// Como todo inquilino é também um morador, os campos RG, órgão emissor, telefone
    /// e estado civil são obrigatórios, assim como nos dependentes.
    /// </summary>
    public Inquilino(
        string nomeCompleto,
        string cpf,
        int quantidadeMoradores,
        DateOnly dataEntrada,
        DateOnly dataVencimentoContrato,
        decimal valorAluguel,
        Guid apartamentoId,
        DateOnly dataNascimento,
        string rg,
        string orgaoEmissor,
        string telefone,
        EstadoCivil estadoCivil,
        List<int>? diasAlertaVencimento = null,
        decimal garagem = 0m)
    {
        ValidarNome(nomeCompleto);
        ValidarCpf(cpf);
        ValidarQuantidadeMoradores(quantidadeMoradores);
        ValidarValorAluguel(valorAluguel);
        ValidarDatas(dataEntrada, dataVencimentoContrato);
        ValidarRg(rg);
        ValidarOrgaoEmissor(orgaoEmissor);
        ValidarTelefone(telefone);

        NomeCompleto = nomeCompleto.Trim();
        Cpf = LimparCpf(cpf);
        QuantidadeMoradores = quantidadeMoradores;
        DataEntrada = dataEntrada;
        DataVencimentoContrato = dataVencimentoContrato;
        ValorAluguel = valorAluguel;
        ApartamentoId = apartamentoId;
        DataNascimento = dataNascimento;
        Rg = rg.Trim();
        OrgaoEmissor = orgaoEmissor.Trim();
        Telefone = telefone.Trim();
        EstadoCivil = estadoCivil;
        DiasAlertaVencimento = diasAlertaVencimento ?? new List<int> { 30, 60, 90 };
        Garagem = garagem < 0 ? 0 : garagem;
    }

    /// <summary>Atualiza as informações básicas do inquilino (sem RG, órgão emissor, telefone e estado civil).</summary>
    public void Atualizar(
        string nomeCompleto,
        int quantidadeMoradores,
        DateOnly dataVencimentoContrato,
        decimal valorAluguel,
        List<int>? diasAlertaVencimento = null,
        decimal garagem = 0m)
    {
        ValidarNome(nomeCompleto);
        ValidarQuantidadeMoradores(quantidadeMoradores);
        ValidarValorAluguel(valorAluguel);

        NomeCompleto = nomeCompleto.Trim();
        QuantidadeMoradores = quantidadeMoradores;
        DataVencimentoContrato = dataVencimentoContrato;
        ValorAluguel = valorAluguel;
        Garagem = garagem < 0 ? 0 : garagem;

        if (diasAlertaVencimento != null)
            DiasAlertaVencimento = diasAlertaVencimento;

        MarcarComoAtualizado();
    }

    /// <summary>Atualiza as informações do inquilino.</summary>
    public void Atualizar(
        string nomeCompleto,
        int quantidadeMoradores,
        DateOnly dataVencimentoContrato,
        decimal valorAluguel,
        string rg,
        string orgaoEmissor,
        string telefone,
        EstadoCivil estadoCivil,
        List<int>? diasAlertaVencimento = null,
        decimal garagem = 0m)
    {
        ValidarNome(nomeCompleto);
        ValidarQuantidadeMoradores(quantidadeMoradores);
        ValidarValorAluguel(valorAluguel);
        ValidarRg(rg);
        ValidarOrgaoEmissor(orgaoEmissor);
        ValidarTelefone(telefone);

        NomeCompleto = nomeCompleto.Trim();
        QuantidadeMoradores = quantidadeMoradores;
        DataVencimentoContrato = dataVencimentoContrato;
        ValorAluguel = valorAluguel;
        Rg = rg.Trim();
        OrgaoEmissor = orgaoEmissor.Trim();
        Telefone = telefone.Trim();
        EstadoCivil = estadoCivil;
        Garagem = garagem < 0 ? 0 : garagem;

        if (diasAlertaVencimento != null)
            DiasAlertaVencimento = diasAlertaVencimento;

        MarcarComoAtualizado();
    }

    /// <summary>
    /// Verifica se o contrato do inquilino vence dentro de um número específico de dias.
    /// Utilizado para disparar alertas de vencimento.
    /// </summary>
    /// <param name="diasAntecedencia">Quantidade de dias para verificar antecedência.</param>
    /// <returns>Verdadeiro se o contrato vence dentro dos dias especificados.</returns>
    public bool ContratoVenceEm(int diasAntecedencia)
    {
        var dataLimite = DateOnly.FromDateTime(DateTime.Today.AddDays(diasAntecedencia));
        return DataVencimentoContrato <= dataLimite && DataVencimentoContrato >= DateOnly.FromDateTime(DateTime.Today);
    }

    /// <summary>
    /// Verifica se algum alerta de vencimento está ativo com base na configuração de alertas.
    /// </summary>
    /// <returns>Lista de dias configurados onde o alerta está ativo no momento.</returns>
    public IEnumerable<int> ObterAlertasAtivos()
    {
        return DiasAlertaVencimento.Where(ContratoVenceEm);
    }

    /// <summary>
    /// Remove formatação do CPF, mantendo apenas os dígitos.
    /// </summary>
    private static string LimparCpf(string cpf)
        => new(cpf.Where(char.IsDigit).ToArray());

    private static void ValidarNome(string nome)
    {
        if (string.IsNullOrWhiteSpace(nome))
            throw new ArgumentException("O nome completo do inquilino não pode ser vazio.", nameof(nome));
    }

    private static void ValidarCpf(string cpf)
    {
        var digitos = new string(cpf.Where(char.IsDigit).ToArray());
        if (digitos.Length != 11)
            throw new ArgumentException("O CPF deve conter 11 dígitos numéricos.", nameof(cpf));
    }

    private static void ValidarRg(string rg)
    {
        if (string.IsNullOrWhiteSpace(rg))
            throw new ArgumentException("O RG do inquilino é obrigatório.", nameof(rg));
    }

    private static void ValidarOrgaoEmissor(string orgaoEmissor)
    {
        if (string.IsNullOrWhiteSpace(orgaoEmissor))
            throw new ArgumentException("O órgão emissor do RG é obrigatório.", nameof(orgaoEmissor));
    }

    private static void ValidarTelefone(string telefone)
    {
        if (string.IsNullOrWhiteSpace(telefone))
            throw new ArgumentException("O telefone do inquilino é obrigatório.", nameof(telefone));
    }

    private static void ValidarQuantidadeMoradores(int quantidade)
    {
        if (quantidade <= 0)
            throw new ArgumentException("A quantidade de moradores deve ser maior que zero.", nameof(quantidade));
    }

    private static void ValidarValorAluguel(decimal valor)
    {
        if (valor <= 0)
            throw new ArgumentException("O valor do aluguel deve ser maior que zero.", nameof(valor));
    }

    private static void ValidarDatas(DateOnly dataEntrada, DateOnly dataVencimento)
    {
        if (dataEntrada >= dataVencimento)
            throw new ArgumentException("A data de entrada deve ser anterior à data de vencimento do contrato.");
    }
}

using BackEndAluguel.Domain.Entidades;

namespace BackEndAluguel.Domain.Interfaces;

/// <summary>
/// Contrato do repositório de hosts (administradores/locadores).
/// </summary>
public interface IHostRepositorio : IRepositorio<Host>
{
    /// <summary>Busca um host pelo e-mail (case-insensitive).</summary>
    Task<Host?> ObterPorEmailAsync(string email, CancellationToken cancellationToken = default);

    /// <summary>Busca um host pelo CPF (somente dígitos).</summary>
    Task<Host?> ObterPorCpfAsync(string cpf, CancellationToken cancellationToken = default);

    /// <summary>Busca um host pelo token de confirmação de e-mail.</summary>
    Task<Host?> ObterPorTokenConfirmacaoAsync(string token, CancellationToken cancellationToken = default);

    /// <summary>Verifica se já existe um host com o e-mail informado.</summary>
    Task<bool> ExisteEmailAsync(string email, CancellationToken cancellationToken = default);

    /// <summary>Verifica se já existe um host com o CPF informado.</summary>
    Task<bool> ExisteCpfAsync(string cpf, CancellationToken cancellationToken = default);
}

using BackEndAluguel.Domain.Entidades;

namespace BackEndAluguel.Domain.Interfaces;

/// <summary>
/// Contrato específico de repositório para a entidade <see cref="Inquilino"/>.
/// Estende o repositório genérico com operações específicas para inquilinos.
/// </summary>
public interface IInquilinoRepositorio : IRepositorio<Inquilino>
{
    /// <summary>
    /// Verifica se já existe um inquilino cadastrado com o CPF informado.
    /// Utilizado para evitar duplicatas no cadastro.
    /// </summary>
    /// <param name="cpf">CPF do inquilino (somente dígitos).</param>
    /// <param name="cancellationToken">Token para cancelamento assíncrono.</param>
    /// <returns>Verdadeiro se já existir um inquilino com este CPF.</returns>
    Task<bool> ExistePorCpfAsync(string cpf, CancellationToken cancellationToken = default);

    /// <summary>
    /// Busca um inquilino pelo CPF.
    /// </summary>
    /// <param name="cpf">CPF do inquilino (somente dígitos).</param>
    /// <param name="cancellationToken">Token para cancelamento assíncrono.</param>
    /// <returns>O inquilino encontrado ou nulo.</returns>
    Task<Inquilino?> ObterPorCpfAsync(string cpf, CancellationToken cancellationToken = default);

    /// <summary>
    /// Retorna todos os inquilinos vinculados a um apartamento específico.
    /// Inclui histórico de inquilinos (não apenas o atual).
    /// </summary>
    /// <param name="apartamentoId">Identificador do apartamento.</param>
    /// <param name="cancellationToken">Token para cancelamento assíncrono.</param>
    /// <returns>Lista de inquilinos do apartamento.</returns>
    Task<IEnumerable<Inquilino>> ObterPorApartamentoAsync(Guid apartamentoId, CancellationToken cancellationToken = default);

    /// <summary>
    /// Retorna os inquilinos cujos contratos vencem dentro do número de dias informado.
    /// Utilizado para geração de alertas de vencimento de contrato.
    /// </summary>
    /// <param name="diasAntecedencia">Quantidade de dias para antecipação do alerta.</param>
    /// <param name="cancellationToken">Token para cancelamento assíncrono.</param>
    /// <returns>Lista de inquilinos com contrato próximo do vencimento.</returns>
    Task<IEnumerable<Inquilino>> ObterComContratoProximoVencimentoAsync(int diasAntecedencia, CancellationToken cancellationToken = default);

    /// <summary>
    /// Busca o inquilino ativo de um apartamento com as faturas incluídas.
    /// </summary>
    /// <param name="apartamentoId">Identificador do apartamento.</param>
    /// <param name="cancellationToken">Token para cancelamento assíncrono.</param>
    /// <returns>O inquilino com as faturas carregadas ou nulo.</returns>
    Task<Inquilino?> ObterComFaturasPorApartamentoAsync(Guid apartamentoId, CancellationToken cancellationToken = default);
}

