using BackEndAluguel.Domain.Entidades;
using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.Metadata.Builders;

namespace BackEndAluguel.Infrastructure.Configuracoes;

/// <summary>
/// Configuração de mapeamento EF Core para a entidade <see cref="Host"/>.
/// Define a tabela "Hosts" com todas as colunas e constraints.
/// </summary>
public class HostConfiguracao : IEntityTypeConfiguration<Host>
{
    public void Configure(EntityTypeBuilder<Host> builder)
    {
        builder.ToTable("Hosts");

        builder.HasKey(h => h.Id);

        builder.Property(h => h.NomeCompleto)
            .IsRequired()
            .HasMaxLength(200);

        builder.Property(h => h.Cpf)
            .IsRequired()
            .HasMaxLength(11)
            .IsFixedLength();

        builder.Property(h => h.DataNascimento)
            .IsRequired();

        builder.Property(h => h.Email)
            .IsRequired()
            .HasMaxLength(200);

        builder.Property(h => h.SenhaHash)
            .IsRequired()
            .HasMaxLength(500);

        builder.Property(h => h.EmailConfirmado)
            .IsRequired()
            .HasDefaultValue(false);

        builder.Property(h => h.TokenConfirmacao)
            .HasMaxLength(100);

        builder.Property(h => h.TokenExpiracaoConfirmacao);

        builder.Property(h => h.CriadoEm)
            .IsRequired();

        builder.Property(h => h.AtualizadoEm);

        // Índices únicos para evitar duplicação
        builder.HasIndex(h => h.Email).IsUnique();
        builder.HasIndex(h => h.Cpf).IsUnique();
        builder.HasIndex(h => h.TokenConfirmacao).IsUnique().HasFilter("[TokenConfirmacao] IS NOT NULL");
    }
}

using BackEndAluguel.Domain.Entidades;
using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.Metadata.Builders;

namespace BackEndAluguel.Infrastructure.Configuracoes;

/// <summary>
/// Configuração do mapeamento da entidade <see cref="Inquilino"/> para o banco de dados.
/// Define todas as colunas, restrições, conversões e relacionamentos.
/// </summary>
public class InquilinoConfiguracao : IEntityTypeConfiguration<Inquilino>
{
    /// <summary>
    /// Configura a tabela, colunas, conversões de tipo e relacionamentos da entidade Inquilino.
    /// </summary>
    /// <param name="builder">Construtor de configuração da entidade.</param>
    public void Configure(EntityTypeBuilder<Inquilino> builder)
    {
        // Nome da tabela no banco de dados
        builder.ToTable("Inquilinos");

        // Chave primária
        builder.HasKey(i => i.Id);

        builder.Property(i => i.Id)
            .HasColumnName("Id")
            .IsRequired();

        // Nome completo — máximo 200 caracteres, obrigatório
        builder.Property(i => i.NomeCompleto)
            .HasColumnName("NomeCompleto")
            .HasMaxLength(200)
            .IsRequired();

        // CPF — 11 dígitos, único no sistema
        builder.Property(i => i.Cpf)
            .HasColumnName("Cpf")
            .HasMaxLength(11)
            .IsRequired();

        // Índice único para garantir CPF único no banco
        builder.HasIndex(i => i.Cpf)
            .IsUnique()
            .HasDatabaseName("IX_Inquilinos_Cpf");

        // Quantidade de moradores
        builder.Property(i => i.QuantidadeMoradores)
            .HasColumnName("QuantidadeMoradores")
            .IsRequired();

        // Datas do contrato — armazenadas como DateOnly no banco
        builder.Property(i => i.DataEntrada)
            .HasColumnName("DataEntrada")
            .IsRequired();

        builder.Property(i => i.DataVencimentoContrato)
            .HasColumnName("DataVencimentoContrato")
            .IsRequired();

        // Valor do aluguel — precisão de 18 dígitos, 2 casas decimais
        builder.Property(i => i.ValorAluguel)
            .HasColumnName("ValorAluguel")
            .HasPrecision(18, 2)
            .IsRequired();

        // Valor da garagem — precisão de 18 dígitos, 2 casas decimais, padrão 0
        builder.Property(i => i.Garagem)
            .HasColumnName("Garagem")
            .HasPrecision(18, 2)
            .IsRequired()
            .HasDefaultValue(0m);

        // DiasAlertaVencimento — armazenada como CSV no banco de dados (ex: "30,60,90").
        // Converte List<int> para string CSV e vice-versa.
        // O ValueComparer garante que o EF Core detecte corretamente mudanças na coleção.
        var diasAlertaProperty = builder.Property(i => i.DiasAlertaVencimento)
            .HasColumnName("DiasAlertaVencimento")
            .HasConversion(
                lista => string.Join(",", lista),
                valor => valor.Split(',', StringSplitOptions.RemoveEmptyEntries)
                              .Select(int.Parse)
                              .ToList())
            .IsRequired();

        // ValueComparer necessário para o EF Core detectar mudanças em coleções (Change Tracking)
        diasAlertaProperty.Metadata.SetValueComparer(new ValueComparer<List<int>>(
            (c1, c2) => c1 != null && c2 != null && c1.SequenceEqual(c2),
            c => c.Aggregate(0, (a, v) => HashCode.Combine(a, v.GetHashCode())),
            c => c.ToList()));

        // Chave estrangeira para Apartamento
        builder.Property(i => i.ApartamentoId)
            .HasColumnName("ApartamentoId")
            .IsRequired();

        // Auditorias de data
        builder.Property(i => i.CriadoEm)
            .HasColumnName("CriadoEm")
            .IsRequired();

        builder.Property(i => i.AtualizadoEm)
            .HasColumnName("AtualizadoEm")
            .IsRequired(false);

        // Relacionamento: 1 Inquilino -> N Dependentes
        builder.HasMany(i => i.Dependentes)
            .WithOne(d => d.Inquilino)
            .HasForeignKey(d => d.InquilinoId)
            .OnDelete(DeleteBehavior.Cascade);

        // =============================================================
        // RELACIONAMENTO: 1 Inquilino -> N Faturas
        // Um inquilino pode ter várias faturas mensais.
        // A exclusão de um inquilino em cascata remove suas faturas.
        // =============================================================
        builder.HasMany(i => i.Faturas)
            .WithOne(f => f.Inquilino)
            .HasForeignKey(f => f.InquilinoId)
            .OnDelete(DeleteBehavior.Cascade);
    }
}

using BackEndAluguel.Domain.Entidades;
using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.Metadata.Builders;

namespace BackEndAluguel.Infrastructure.Configuracoes;

/// <summary>
/// Configuração do mapeamento da entidade <see cref="Inquilino"/> para o banco de dados.
/// Define todas as colunas, restrições, conversões e relacionamentos.
/// </summary>
public class InquilinoConfiguracao : IEntityTypeConfiguration<Inquilino>
{
    /// <summary>
    /// Configura a tabela, colunas, conversões de tipo e relacionamentos da entidade Inquilino.
    /// </summary>
    /// <param name="builder">Construtor de configuração da entidade.</param>
    public void Configure(EntityTypeBuilder<Inquilino> builder)
    {
        // Nome da tabela no banco de dados
        builder.ToTable("Inquilinos");

        // Chave primária
        builder.HasKey(i => i.Id);

        builder.Property(i => i.Id)
            .HasColumnName("Id")
            .IsRequired();

        // Nome completo — máximo 200 caracteres, obrigatório
        builder.Property(i => i.NomeCompleto)
            .HasColumnName("NomeCompleto")
            .HasMaxLength(200)
            .IsRequired();

        // CPF — 11 dígitos, único no sistema
        builder.Property(i => i.Cpf)
            .HasColumnName("Cpf")
            .HasMaxLength(11)
            .IsRequired();

        // Índice único para garantir CPF único no banco
        builder.HasIndex(i => i.Cpf)
            .IsUnique()
            .HasDatabaseName("IX_Inquilinos_Cpf");

        // RG — obrigatório (inquilino é também um morador)
        builder.Property(i => i.Rg)
            .HasColumnName("Rg")
            .HasMaxLength(20)
            .IsRequired();

        // Órgão emissor do RG
        builder.Property(i => i.OrgaoEmissor)
            .HasColumnName("OrgaoEmissor")
            .HasMaxLength(20)
            .IsRequired();

        // Telefone de contato
        builder.Property(i => i.Telefone)
            .HasColumnName("Telefone")
            .HasMaxLength(20)
            .IsRequired();

        // Estado civil
        builder.Property(i => i.EstadoCivil)
            .HasColumnName("EstadoCivil")
            .IsRequired();

        // Quantidade de moradores
        builder.Property(i => i.QuantidadeMoradores)
            .HasColumnName("QuantidadeMoradores")
            .IsRequired();

        // Data de nascimento — usada como segundo fator no login do inquilino
        builder.Property(i => i.DataNascimento)
            .HasColumnName("DataNascimento")
            .IsRequired();

        // Datas do contrato — armazenadas como DateOnly no banco
        builder.Property(i => i.DataEntrada)
            .HasColumnName("DataEntrada")
            .IsRequired();

        builder.Property(i => i.DataVencimentoContrato)
            .HasColumnName("DataVencimentoContrato")
            .IsRequired();

        // Valor do aluguel — precisão de 18 dígitos, 2 casas decimais
        builder.Property(i => i.ValorAluguel)
            .HasColumnName("ValorAluguel")
            .HasPrecision(18, 2)
            .IsRequired();

        // Valor da garagem — precisão de 18 dígitos, 2 casas decimais, padrão 0
        builder.Property(i => i.Garagem)
            .HasColumnName("Garagem")
            .HasPrecision(18, 2)
            .IsRequired()
            .HasDefaultValue(0m);

        // DiasAlertaVencimento — armazenada como CSV no banco de dados (ex: "30,60,90").
        // Converte List<int> para string CSV e vice-versa.
        // O ValueComparer garante que o EF Core detecte corretamente mudanças na coleção.
        var diasAlertaProperty = builder.Property(i => i.DiasAlertaVencimento)
            .HasColumnName("DiasAlertaVencimento")
            .HasConversion(
                lista => string.Join(",", lista),
                valor => valor.Split(',', StringSplitOptions.RemoveEmptyEntries)
                              .Select(int.Parse)
                              .ToList())
            .IsRequired();

        // ValueComparer necessário para o EF Core detectar mudanças em coleções (Change Tracking)
        diasAlertaProperty.Metadata.SetValueComparer(new ValueComparer<List<int>>(
            (c1, c2) => c1 != null && c2 != null && c1.SequenceEqual(c2),
            c => c.Aggregate(0, (a, v) => HashCode.Combine(a, v.GetHashCode())),
            c => c.ToList()));

        // Chave estrangeira para Apartamento
        builder.Property(i => i.ApartamentoId)
            .HasColumnName("ApartamentoId")
            .IsRequired();

        // Auditorias de data
        builder.Property(i => i.CriadoEm)
            .HasColumnName("CriadoEm")
            .IsRequired();

        builder.Property(i => i.AtualizadoEm)
            .HasColumnName("AtualizadoEm")
            .IsRequired(false);

        // Relacionamento: 1 Inquilino -> N Dependentes
        builder.HasMany(i => i.Dependentes)
            .WithOne(d => d.Inquilino)
            .HasForeignKey(d => d.InquilinoId)
            .OnDelete(DeleteBehavior.Cascade);

        // =============================================================
        // RELACIONAMENTO: 1 Inquilino -> N Faturas
        // Um inquilino pode ter várias faturas mensais.
        // A exclusão de um inquilino em cascata remove suas faturas.
        // =============================================================
        builder.HasMany(i => i.Faturas)
            .WithOne(f => f.Inquilino)
            .HasForeignKey(f => f.InquilinoId)
            .OnDelete(DeleteBehavior.Cascade);
    }
}

using BackEndAluguel.Domain.Entidades;
using BackEndAluguel.Infrastructure.Configuracoes;
using Microsoft.EntityFrameworkCore;

namespace BackEndAluguel.Infrastructure.Contexto;

/// <summary>
/// Contexto principal do Entity Framework Core para o sistema de gerenciamento de aluguéis.
/// Centraliza o acesso ao banco de dados e aplica todas as configurações de mapeamento das entidades.
/// 
/// Relações gerenciadas:
/// - Apartamento (1) → Inquilinos (N): Um apartamento possui vários inquilinos ao longo do tempo.
/// - Inquilino (1) → Faturas (N): Um inquilino possui várias faturas mensais.
/// </summary>
public class AluguelDbContext : DbContext
{
    /// <summary>
    /// Inicializa o contexto com as opções de configuração fornecidas via injeção de dependência.
    /// </summary>
    /// <param name="opcoes">Opções de configuração do DbContext (connection string, provider, etc.).</param>
    public AluguelDbContext(DbContextOptions<AluguelDbContext> opcoes) : base(opcoes)
    {
    }

    // =============================================================
    // DbSets — Representam as tabelas no banco de dados
    // =============================================================

    /// <summary>
    /// Representa a tabela "Apartamentos" no banco de dados.
    /// Permite realizar operações CRUD sobre os apartamentos cadastrados.
    /// </summary>
    public DbSet<Apartamento> Apartamentos => Set<Apartamento>();

    /// <summary>
    /// Representa a tabela "Inquilinos" no banco de dados.
    /// Permite realizar operações CRUD sobre os inquilinos cadastrados.
    /// </summary>
    public DbSet<Inquilino> Inquilinos => Set<Inquilino>();

    /// <summary>
    /// Representa a tabela "Faturas" no banco de dados.
    /// Permite realizar operações CRUD sobre as faturas mensais.
    /// </summary>
    public DbSet<Fatura> Faturas => Set<Fatura>();

    /// <summary>
    /// Representa a tabela "Dependentes" no banco de dados.
    /// Permite realizar operações CRUD sobre os dependentes cadastrados.
    /// </summary>
    public DbSet<Dependente> Dependentes => Set<Dependente>();

    /// <summary>
    /// Representa a tabela "Configuracoes" no banco de dados.
    /// Permite realizar operações CRUD sobre as configurações do sistema.
    /// </summary>
    public DbSet<Configuracao> Configuracoes => Set<Configuracao>();

    /// <summary>
    /// Representa a tabela "GastosManutencao" no banco de dados.
    /// </summary>
    public DbSet<GastoManutencao> GastosManutencao => Set<GastoManutencao>();

    /// <summary>
    /// Representa a tabela "ContratosInquilino" no banco de dados.
    /// </summary>
    public DbSet<ContratoInquilino> ContratosInquilino => Set<ContratoInquilino>();

    /// <summary>
    /// Configura o mapeamento das entidades para o banco de dados aplicando as classes de configuração
    /// do padrão IEntityTypeConfiguration, mantendo a separação de responsabilidades (SRP).
    /// </summary>
    /// <param name="modelBuilder">Construtor do modelo de dados do EF Core.</param>
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        base.OnModelCreating(modelBuilder);

        // Aplica automaticamente todas as configurações de entidade
        // definidas na assembly da infraestrutura (IEntityTypeConfiguration<T>)
        modelBuilder.ApplyConfigurationsFromAssembly(typeof(AluguelDbContext).Assembly);

        // Seed do registro singleton de Configuracao
        modelBuilder.Entity<Configuracao>().HasData(new
        {
            Id = ConfiguracaoConfiguracao.ConfiguracaoId,
            KwhValor = 0.0m,
            ValorAgua = 0.0m,
            CriadoEm = new DateTime(2025, 1, 1, 0, 0, 0, DateTimeKind.Utc),
            AtualizadoEm = (DateTime?)null
        });
    }
}

