using BackEndAluguel.Domain.Entidades;
using BackEndAluguel.Domain.Interfaces;
using BackEndAluguel.Infrastructure.Contexto;
using Microsoft.EntityFrameworkCore;

namespace BackEndAluguel.Infrastructure.Repositorios;

/// <summary>
/// Implementação concreta do repositório de hosts.
/// Herda as operações CRUD genéricas do <see cref="RepositorioBase{T}"/>.
/// </summary>
public class HostRepositorio : RepositorioBase<Host>, IHostRepositorio
{
    public HostRepositorio(AluguelDbContext contexto) : base(contexto) { }

    /// <inheritdoc />
    public async Task<Host?> ObterPorEmailAsync(string email, CancellationToken cancellationToken = default)
        => await DbSet.FirstOrDefaultAsync(
            h => h.Email == email.ToLowerInvariant(), cancellationToken);

    /// <inheritdoc />
    public async Task<Host?> ObterPorCpfAsync(string cpf, CancellationToken cancellationToken = default)
        => await DbSet.FirstOrDefaultAsync(h => h.Cpf == cpf, cancellationToken);

    /// <inheritdoc />
    public async Task<Host?> ObterPorTokenConfirmacaoAsync(string token, CancellationToken cancellationToken = default)
        => await DbSet.FirstOrDefaultAsync(h => h.TokenConfirmacao == token, cancellationToken);

    /// <inheritdoc />
    public async Task<bool> ExisteEmailAsync(string email, CancellationToken cancellationToken = default)
        => await DbSet.AnyAsync(h => h.Email == email.ToLowerInvariant(), cancellationToken);

    /// <inheritdoc />
    public async Task<bool> ExisteCpfAsync(string cpf, CancellationToken cancellationToken = default)
        => await DbSet.AnyAsync(h => h.Cpf == cpf, cancellationToken);
}

using BackEndAluguel.Domain.Entidades;
using BackEndAluguel.Domain.Interfaces;
using BackEndAluguel.Infrastructure.Contexto;
using Microsoft.EntityFrameworkCore;

namespace BackEndAluguel.Infrastructure.Repositorios;

/// <summary>
/// Implementação concreta do repositório de <see cref="Inquilino"/>.
/// Herda as operações genéricas do <see cref="RepositorioBase{T}"/> e adiciona
/// queries específicas para inquilinos.
/// </summary>
public class InquilinoRepositorio : RepositorioBase<Inquilino>, IInquilinoRepositorio
{
    /// <summary>
    /// Inicializa o repositório com o contexto do banco de dados.
    /// </summary>
    public InquilinoRepositorio(AluguelDbContext contexto) : base(contexto)
    {
    }

    /// <summary>
    /// Verifica se já existe um inquilino cadastrado com o CPF informado.
    /// </summary>
    public async Task<bool> ExistePorCpfAsync(string cpf, CancellationToken cancellationToken = default)
        => await DbSet.AnyAsync(i => i.Cpf == cpf, cancellationToken);

    /// <summary>
    /// Busca um inquilino pelo CPF.
    /// </summary>
    public async Task<Inquilino?> ObterPorCpfAsync(string cpf, CancellationToken cancellationToken = default)
        => await DbSet.FirstOrDefaultAsync(i => i.Cpf == cpf, cancellationToken);

    /// <summary>
    /// Retorna todos os inquilinos vinculados a um apartamento específico.
    /// </summary>
    public async Task<IEnumerable<Inquilino>> ObterPorApartamentoAsync(Guid apartamentoId, CancellationToken cancellationToken = default)
        => await DbSet.AsNoTracking()
            .Where(i => i.ApartamentoId == apartamentoId)
            .OrderByDescending(i => i.DataEntrada)
            .ToListAsync(cancellationToken);

    /// <summary>
    /// Retorna os inquilinos cujos contratos vencem dentro do número de dias informado.
    /// </summary>
    public async Task<IEnumerable<Inquilino>> ObterComContratoProximoVencimentoAsync(
        int diasAntecedencia, CancellationToken cancellationToken = default)
    {
        var hoje = DateOnly.FromDateTime(DateTime.Today);
        var dataLimite = DateOnly.FromDateTime(DateTime.Today.AddDays(diasAntecedencia));

        return await DbSet.AsNoTracking()
            .Where(i => i.DataVencimentoContrato >= hoje && i.DataVencimentoContrato <= dataLimite)
            .OrderBy(i => i.DataVencimentoContrato)
            .ToListAsync(cancellationToken);
    }

    /// <summary>
    /// Busca o inquilino ativo de um apartamento com as faturas carregadas via Include.
    /// </summary>
    public async Task<Inquilino?> ObterComFaturasPorApartamentoAsync(
        Guid apartamentoId, CancellationToken cancellationToken = default)
        => await DbSet
            .Include(i => i.Faturas)
            .FirstOrDefaultAsync(i => i.ApartamentoId == apartamentoId, cancellationToken);
}

using BackEndAluguel.Domain.Entidades;
using BackEndAluguel.Domain.Interfaces;
using BackEndAluguel.Infrastructure.Contexto;
using Microsoft.EntityFrameworkCore;

namespace BackEndAluguel.Infrastructure.Repositorios;

/// <summary>
/// Implementação concreta do repositório de <see cref="Inquilino"/>.
/// Herda as operações genéricas do <see cref="RepositorioBase{T}"/> e adiciona
/// queries específicas para inquilinos.
/// </summary>
public class InquilinoRepositorio : RepositorioBase<Inquilino>, IInquilinoRepositorio
{
    /// <summary>
    /// Inicializa o repositório com o contexto do banco de dados.
    /// </summary>
    public InquilinoRepositorio(AluguelDbContext contexto) : base(contexto)
    {
    }

    /// <summary>
    /// Busca um inquilino pelo ID incluindo o Apartamento vinculado.
    /// Sobrescreve o método base para garantir que a propriedade de navegação seja carregada.
    /// </summary>
    public override async Task<Inquilino?> ObterPorIdAsync(Guid id, CancellationToken cancellationToken = default)
        => await DbSet
            .Include(i => i.Apartamento)
            .FirstOrDefaultAsync(i => i.Id == id, cancellationToken);

    /// <summary>
    /// Verifica se já existe um inquilino cadastrado com o CPF informado.
    /// </summary>
    public async Task<bool> ExistePorCpfAsync(string cpf, CancellationToken cancellationToken = default)
        => await DbSet.AnyAsync(i => i.Cpf == cpf, cancellationToken);

    /// <summary>
    /// Busca um inquilino pelo CPF.
    /// </summary>
    public async Task<Inquilino?> ObterPorCpfAsync(string cpf, CancellationToken cancellationToken = default)
        => await DbSet.FirstOrDefaultAsync(i => i.Cpf == cpf, cancellationToken);

    /// <summary>
    /// Retorna todos os inquilinos vinculados a um apartamento específico.
    /// </summary>
    public async Task<IEnumerable<Inquilino>> ObterPorApartamentoAsync(Guid apartamentoId, CancellationToken cancellationToken = default)
        => await DbSet.AsNoTracking()
            .Where(i => i.ApartamentoId == apartamentoId)
            .OrderByDescending(i => i.DataEntrada)
            .ToListAsync(cancellationToken);

    /// <summary>
    /// Retorna os inquilinos cujos contratos vencem dentro do número de dias informado.
    /// </summary>
    public async Task<IEnumerable<Inquilino>> ObterComContratoProximoVencimentoAsync(
        int diasAntecedencia, CancellationToken cancellationToken = default)
    {
        var hoje = DateOnly.FromDateTime(DateTime.Today);
        var dataLimite = DateOnly.FromDateTime(DateTime.Today.AddDays(diasAntecedencia));

        return await DbSet.AsNoTracking()
            .Where(i => i.DataVencimentoContrato >= hoje && i.DataVencimentoContrato <= dataLimite)
            .OrderBy(i => i.DataVencimentoContrato)
            .ToListAsync(cancellationToken);
    }

    /// <summary>
    /// Busca o inquilino ativo de um apartamento com as faturas carregadas via Include.
    /// </summary>
    public async Task<Inquilino?> ObterComFaturasPorApartamentoAsync(
        Guid apartamentoId, CancellationToken cancellationToken = default)
        => await DbSet
            .Include(i => i.Faturas)
            .FirstOrDefaultAsync(i => i.ApartamentoId == apartamentoId, cancellationToken);

    /// <summary>
    /// Autentica inquilino pelo CPF e data de nascimento (segundo fator para login).
    /// </summary>
    public async Task<Inquilino?> ObterPorCpfEDataNascimentoAsync(
        string cpf, DateOnly dataNascimento, CancellationToken cancellationToken = default)
        => await DbSet.FirstOrDefaultAsync(
            i => i.Cpf == cpf && i.DataNascimento == dataNascimento,
            cancellationToken);
}

using System.Net;
using System.Net.Mail;
using BackEndAluguel.Application.Auth;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;

namespace BackEndAluguel.Infrastructure.Servicos;

/// <summary>
/// Implementação do serviço de e-mail usando SMTP via System.Net.Mail.
/// Configurações lidas do appsettings.json (seção "Email").
/// </summary>
public class EmailServico : IEmailServico
{
    private readonly IConfiguration _configuracao;
    private readonly ILogger<EmailServico> _logger;

    public EmailServico(IConfiguration configuracao, ILogger<EmailServico> logger)
    {
        _configuracao = configuracao;
        _logger = logger;
    }

    /// <summary>
    /// Envia o e-mail de confirmação de conta com o link para ativar a conta.
    /// O link aponta para a URL do frontend configurada em "Email:UrlFrontEnd".
    /// </summary>
    public async Task EnviarConfirmacaoContaAsync(
        string destinatario,
        string nomeDestinatario,
        string tokenConfirmacao,
        CancellationToken cancellationToken = default)
    {
        var urlFrontEnd = _configuracao["Email:UrlFrontEnd"] ?? "http://localhost:3000";
        var linkConfirmacao = $"{urlFrontEnd}/confirmar-email?token={tokenConfirmacao}";

        var assunto = "GestAluguel — Confirme sua conta";
        var corpo = MontarCorpoEmail(nomeDestinatario, linkConfirmacao);

        await EnviarAsync(destinatario, assunto, corpo, cancellationToken);

        _logger.LogInformation("E-mail de confirmação enviado para {Email}", destinatario);
    }

    // ─── Métodos auxiliares ────────────────────────────────────────────────

    private async Task EnviarAsync(string destinatario, string assunto, string corpo, CancellationToken cancellationToken)
    {
        var host = _configuracao["Email:Smtp:Host"] ?? throw new InvalidOperationException("Email:Smtp:Host não configurado.");
        var porta = int.TryParse(_configuracao["Email:Smtp:Porta"], out var p) ? p : 587;
        var usuario = _configuracao["Email:Smtp:Usuario"] ?? throw new InvalidOperationException("Email:Smtp:Usuario não configurado.");
        var senha = _configuracao["Email:Smtp:Senha"] ?? throw new InvalidOperationException("Email:Smtp:Senha não configurada.");
        var remetente = _configuracao["Email:Remetente"] ?? usuario;
        var nomeRemetente = _configuracao["Email:NomeRemetente"] ?? "GestAluguel";
        var ssl = bool.TryParse(_configuracao["Email:Smtp:UsarSsl"], out var s) && s;

        using var client = new SmtpClient(host, porta)
        {
            Credentials = new NetworkCredential(usuario, senha),
            EnableSsl = ssl,
            DeliveryMethod = SmtpDeliveryMethod.Network
        };

        using var mensagem = new MailMessage
        {
            From = new MailAddress(remetente, nomeRemetente),
            Subject = assunto,
            Body = corpo,
            IsBodyHtml = true
        };
        mensagem.To.Add(destinatario);

        await client.SendMailAsync(mensagem, cancellationToken);
    }

    private static string MontarCorpoEmail(string nomeDestinatario, string linkConfirmacao) => $"""
        <!DOCTYPE html>
        <html lang="pt-BR">
        <head><meta charset="UTF-8"><title>Confirme sua conta</title></head>
        <body style="font-family: Arial, sans-serif; background: #f4f4f4; padding: 24px;">
          <div style="max-width: 560px; margin: 0 auto; background: #fff; border-radius: 8px; padding: 32px; box-shadow: 0 2px 8px rgba(0,0,0,0.08);">
            <h2 style="color: #1a73e8;">Bem-vindo ao GestAluguel!</h2>
            <p>Olá, <strong>{nomeDestinatario}</strong>!</p>
            <p>Seu cadastro foi realizado com sucesso. Para ativar sua conta e começar a usar a plataforma, clique no botão abaixo:</p>
            <div style="text-align: center; margin: 32px 0;">
              <a href="{linkConfirmacao}"
                 style="background: #1a73e8; color: #fff; padding: 14px 28px; border-radius: 6px; text-decoration: none; font-size: 16px; font-weight: bold;">
                Confirmar minha conta
              </a>
            </div>
            <p style="color: #666; font-size: 13px;">Este link é válido por <strong>48 horas</strong>.</p>
            <p style="color: #666; font-size: 13px;">Se você não criou esta conta, ignore este e-mail.</p>
            <hr style="border: none; border-top: 1px solid #eee; margin: 24px 0;">
            <p style="color: #aaa; font-size: 12px; text-align: center;">© {DateTime.UtcNow.Year} GestAluguel. Todos os direitos reservados.</p>
          </div>
        </body>
        </html>
        """;
}

using System.IdentityModel.Tokens.Jwt;
using System.Security.Claims;
using System.Text;
using BackEndAluguel.Application.Auth;
using Microsoft.Extensions.Configuration;
using Microsoft.IdentityModel.Tokens;

namespace BackEndAluguel.Infrastructure.Servicos;

/// <summary>
/// Implementacao concreta do servico de geracao de tokens JWT.
/// Utiliza a chave secreta, issuer e audience definidos no appsettings.json.
/// </summary>
public class JwtServico : IJwtServico
{
    private readonly IConfiguration _configuracao;

    /// <summary>Inicializa o servico JWT com as configuracoes da aplicacao.</summary>
    public JwtServico(IConfiguration configuracao)
    {
        _configuracao = configuracao;
    }

    /// <summary>
    /// Gera um token JWT para o administrador (host/locador) autenticado pelo banco de dados.
    /// </summary>
    public (string Token, DateTime Expiracao) GerarTokenHost(Guid hostId, string nomeCompleto, string email)
    {
        var claims = new List<Claim>
        {
            new(ClaimTypes.NameIdentifier, hostId.ToString()),
            new(ClaimTypes.Name, nomeCompleto),
            new(ClaimTypes.Email, email),
            new(ClaimTypes.Role, "Host"),
            new("hostId", hostId.ToString()),
            new(JwtRegisteredClaimNames.Sub, hostId.ToString()),
            new(JwtRegisteredClaimNames.Jti, Guid.NewGuid().ToString())
        };

        return GerarToken(claims);
    }

    /// <summary>
    /// Gera um token JWT para um inquilino autenticado.
    /// Retorna o token assinado e a data de expiracao UTC.
    /// </summary>
    public (string Token, DateTime Expiracao) GerarTokenInquilino(Guid inquilinoId, string nomeCompleto, string cpf)
    {
        var claims = new List<Claim>
        {
            new(ClaimTypes.NameIdentifier, inquilinoId.ToString()),
            new(ClaimTypes.Name, nomeCompleto),
            new(ClaimTypes.Role, "Inquilino"),
            new("cpf", cpf),
            new("inquilinoId", inquilinoId.ToString()),
            new(JwtRegisteredClaimNames.Sub, inquilinoId.ToString()),
            new(JwtRegisteredClaimNames.Jti, Guid.NewGuid().ToString())
        };

        return GerarToken(claims);
    }

    /// <summary>
    /// Metodo auxiliar que assina e serializa o token JWT com as claims fornecidas.
    /// Utiliza HMAC-SHA256 com a chave secreta do appsettings.json.
    /// </summary>
    private (string Token, DateTime Expiracao) GerarToken(IEnumerable<Claim> claims)
    {
        var chaveSecreta = _configuracao["Jwt:SecretKey"]
            ?? throw new InvalidOperationException("Chave secreta JWT nao configurada.");

        var issuer = _configuracao["Jwt:Issuer"] ?? "GestAluguelAPI";
        var audience = _configuracao["Jwt:Audience"] ?? "GestAluguelFrontEnd";
        var horasExpiracao = int.TryParse(_configuracao["Jwt:ExpiracaoHoras"], out var h) ? h : 24;
        var expiracao = DateTime.UtcNow.AddHours(horasExpiracao);

        var chaveSimetrica = new SymmetricSecurityKey(Encoding.UTF8.GetBytes(chaveSecreta));
        var credenciais = new SigningCredentials(chaveSimetrica, SecurityAlgorithms.HmacSha256);

        var token = new JwtSecurityToken(
            issuer: issuer,
            audience: audience,
            claims: claims,
            expires: expiracao,
            signingCredentials: credenciais);

        return (new JwtSecurityTokenHandler().WriteToken(token), expiracao);
    }
}

using System.Security.Cryptography;
using BackEndAluguel.Application.Auth;

namespace BackEndAluguel.Infrastructure.Servicos;

/// <summary>
/// Implementação de hashing e verificação de senhas usando PBKDF2-SHA256.
/// Armazena o salt embutido no hash em Base64 — sem dependências externas.
/// Formato: Base64(salt[16] + hash[32]) = 48 bytes = 64 caracteres Base64.
/// </summary>
public class SenhaServico : ISenhaServico
{
    private const int TamanhoSalt = 16;
    private const int TamanhoHash = 32;
    private const int Iteracoes = 100_000;

    /// <summary>
    /// Gera um hash PBKDF2-SHA256 da senha em texto plano com salt aleatório.
    /// </summary>
    public string HashearSenha(string senhaPlana)
    {
        var salt = RandomNumberGenerator.GetBytes(TamanhoSalt);
        var hash = Rfc2898DeriveBytes.Pbkdf2(senhaPlana, salt, Iteracoes, HashAlgorithmName.SHA256, TamanhoHash);

        var resultado = new byte[TamanhoSalt + TamanhoHash];
        Buffer.BlockCopy(salt, 0, resultado, 0, TamanhoSalt);
        Buffer.BlockCopy(hash, 0, resultado, TamanhoSalt, TamanhoHash);

        return Convert.ToBase64String(resultado);
    }

    /// <summary>
    /// Verifica se a senha em texto plano corresponde ao hash armazenado.
    /// Usa comparação de tempo constante para evitar ataques de timing.
    /// </summary>
    public bool VerificarSenha(string senhaPlana, string hashArmazenado)
    {
        byte[] bytes;
        try { bytes = Convert.FromBase64String(hashArmazenado); }
        catch { return false; }

        if (bytes.Length != TamanhoSalt + TamanhoHash)
            return false;

        var salt = bytes[..TamanhoSalt];
        var hashEsperado = bytes[TamanhoSalt..];
        var hashCalculado = Rfc2898DeriveBytes.Pbkdf2(senhaPlana, salt, Iteracoes, HashAlgorithmName.SHA256, TamanhoHash);

        return CryptographicOperations.FixedTimeEquals(hashEsperado, hashCalculado);
    }
}

using BackEndAluguel.Application.Comum.Excecoes;
using BackEndAluguel.Application.Inquilinos.Comandos;
using BackEndAluguel.Application.Inquilinos.Manipuladores;
using BackEndAluguel.Domain.Entidades;
using BackEndAluguel.Domain.Interfaces;
using FluentAssertions;
using Moq;

namespace BackEndAluguel.Tests.Aplicacao;

/// <summary>
/// Testes unitários para os manipuladores CQRS de Inquilino.
/// Usa Moq para simular os repositórios e validar o comportamento dos handlers.
/// </summary>
public class InquilinoManipuladorTestes
{
    private readonly Mock<IInquilinoRepositorio> _inquilinoRepositorioMock;
    private readonly Mock<IApartamentoRepositorio> _apartamentoRepositorioMock;

    private static readonly Guid ApartamentoId = Guid.NewGuid();
    private static readonly DateOnly DataEntrada = new(2024, 1, 1);
    private static readonly DateOnly DataVencimento = new(2026, 12, 31);

    /// <summary>
    /// Inicializa os mocks antes de cada teste.
    /// </summary>
    public InquilinoManipuladorTestes()
    {
        _inquilinoRepositorioMock = new Mock<IInquilinoRepositorio>();
        _apartamentoRepositorioMock = new Mock<IApartamentoRepositorio>();
    }

    // =====================================================
    // Testes de CriarInquilinoManipulador
    // =====================================================

    /// <summary>
    /// Verifica que criar inquilino com dados válidos retorna DTO e marca o apartamento como ocupado.
    /// </summary>
    [Fact]
    public async Task CriarInquilino_DadosValidos_DeveCriarVincularApartamentoERetornarDto()
    {
        // Arrange
        var apartamento = new Apartamento("101", "A");

        _inquilinoRepositorioMock.Setup(r => r.ExistePorCpfAsync("12345678901", It.IsAny<CancellationToken>()))
            .ReturnsAsync(false);
        _apartamentoRepositorioMock.Setup(r => r.ObterPorIdAsync(ApartamentoId, It.IsAny<CancellationToken>()))
            .ReturnsAsync(apartamento);
        _inquilinoRepositorioMock.Setup(r => r.AdicionarAsync(It.IsAny<Inquilino>(), It.IsAny<CancellationToken>()))
            .Returns(Task.CompletedTask);
        _inquilinoRepositorioMock.Setup(r => r.SalvarAlteracoesAsync(It.IsAny<CancellationToken>()))
            .ReturnsAsync(1);

        var manipulador = new CriarInquilinoManipulador(_inquilinoRepositorioMock.Object, _apartamentoRepositorioMock.Object);
        var comando = new CriarInquilinoComando("João da Silva", "12345678901", 2, DataEntrada, DataVencimento, 1500m, ApartamentoId);

        // Act
        var resultado = await manipulador.Handle(comando, CancellationToken.None);

        // Assert
        resultado.Should().NotBeNull();
        resultado.NomeCompleto.Should().Be("João da Silva");
        resultado.Cpf.Should().Be("12345678901");
        resultado.ValorAluguel.Should().Be(1500m);
        resultado.ApartamentoId.Should().Be(ApartamentoId);

        // Deve ter marcado o apartamento como ocupado
        apartamento.Ocupado.Should().BeTrue();
        _apartamentoRepositorioMock.Verify(r => r.Atualizar(apartamento), Times.Once);
    }

    /// <summary>
    /// Verifica que tentar cadastrar inquilino com CPF duplicado lança RegraDeNegocioExcecao.
    /// </summary>
    [Fact]
    public async Task CriarInquilino_CpfJaCadastrado_DeveLancarRegraDeNegocioExcecao()
    {
        // Arrange
        _inquilinoRepositorioMock.Setup(r => r.ExistePorCpfAsync("12345678901", It.IsAny<CancellationToken>()))
            .ReturnsAsync(true);

        var manipulador = new CriarInquilinoManipulador(_inquilinoRepositorioMock.Object, _apartamentoRepositorioMock.Object);
        var comando = new CriarInquilinoComando("João", "12345678901", 1, DataEntrada, DataVencimento, 1000m, ApartamentoId);

        // Act
        var acao = async () => await manipulador.Handle(comando, CancellationToken.None);

        // Assert
        await acao.Should().ThrowAsync<RegraDeNegocioExcecao>()
            .WithMessage("*CPF*");

        _inquilinoRepositorioMock.Verify(r => r.AdicionarAsync(It.IsAny<Inquilino>(), It.IsAny<CancellationToken>()), Times.Never);
    }

    /// <summary>
    /// Verifica que tentar criar inquilino com apartamento inexistente lança EntidadeNaoEncontradaExcecao.
    /// </summary>
    [Fact]
    public async Task CriarInquilino_ApartamentoNaoEncontrado_DeveLancarEntidadeNaoEncontradaExcecao()
    {
        // Arrange
        _inquilinoRepositorioMock.Setup(r => r.ExistePorCpfAsync(It.IsAny<string>(), It.IsAny<CancellationToken>()))
            .ReturnsAsync(false);
        _apartamentoRepositorioMock.Setup(r => r.ObterPorIdAsync(It.IsAny<Guid>(), It.IsAny<CancellationToken>()))
            .ReturnsAsync((Apartamento?)null);

        var manipulador = new CriarInquilinoManipulador(_inquilinoRepositorioMock.Object, _apartamentoRepositorioMock.Object);
        var comando = new CriarInquilinoComando("João", "12345678901", 1, DataEntrada, DataVencimento, 1000m, Guid.NewGuid());

        // Act
        var acao = async () => await manipulador.Handle(comando, CancellationToken.None);

        // Assert
        await acao.Should().ThrowAsync<EntidadeNaoEncontradaExcecao>();
    }

    // =====================================================
    // Testes de RemoverInquilinoManipulador
    // =====================================================

    /// <summary>
    /// Verifica que remover inquilino existente libera o apartamento.
    /// </summary>
    [Fact]
    public async Task RemoverInquilino_InquilinoExistente_DeveRemoverELiberarApartamento()
    {
        // Arrange
        var apartamento = new Apartamento("101", "A");
        apartamento.MarcarComoOcupado();

        var inquilino = new Inquilino("João", "12345678901", 1, DataEntrada, DataVencimento, 1000m, apartamento.Id);

        _inquilinoRepositorioMock.Setup(r => r.ObterPorIdAsync(inquilino.Id, It.IsAny<CancellationToken>()))
            .ReturnsAsync(inquilino);
        _apartamentoRepositorioMock.Setup(r => r.ObterPorIdAsync(inquilino.ApartamentoId, It.IsAny<CancellationToken>()))
            .ReturnsAsync(apartamento);
        _inquilinoRepositorioMock.Setup(r => r.SalvarAlteracoesAsync(It.IsAny<CancellationToken>()))
            .ReturnsAsync(1);

        var manipulador = new RemoverInquilinoManipulador(_inquilinoRepositorioMock.Object, _apartamentoRepositorioMock.Object);
        var comando = new RemoverInquilinoComando(inquilino.Id);

        // Act
        var resultado = await manipulador.Handle(comando, CancellationToken.None);

        // Assert
        resultado.Should().BeTrue();
        apartamento.Ocupado.Should().BeFalse();
        _inquilinoRepositorioMock.Verify(r => r.Remover(inquilino), Times.Once);
        _apartamentoRepositorioMock.Verify(r => r.Atualizar(apartamento), Times.Once);
    }

    // =====================================================
    // Testes de AtualizarInquilinoManipulador
    // =====================================================

    /// <summary>
    /// Verifica que atualizar inquilino existente aplica e persiste as alterações.
    /// </summary>
    [Fact]
    public async Task AtualizarInquilino_InquilinoExistente_DeveAtualizarERetornarDto()
    {
        // Arrange
        var inquilino = new Inquilino("João", "12345678901", 1, DataEntrada, DataVencimento, 1000m, ApartamentoId);

        _inquilinoRepositorioMock.Setup(r => r.ObterPorIdAsync(inquilino.Id, It.IsAny<CancellationToken>()))
            .ReturnsAsync(inquilino);
        _inquilinoRepositorioMock.Setup(r => r.SalvarAlteracoesAsync(It.IsAny<CancellationToken>()))
            .ReturnsAsync(1);

        var manipulador = new AtualizarInquilinoManipulador(_inquilinoRepositorioMock.Object);
        var comando = new AtualizarInquilinoComando(inquilino.Id, "Pedro Santos", 3, new DateOnly(2027, 6, 30), 1800m);

        // Act
        var resultado = await manipulador.Handle(comando, CancellationToken.None);

        // Assert
        resultado.NomeCompleto.Should().Be("Pedro Santos");
        resultado.QuantidadeMoradores.Should().Be(3);
        resultado.ValorAluguel.Should().Be(1800m);
        _inquilinoRepositorioMock.Verify(r => r.Atualizar(inquilino), Times.Once);
    }
}

using BackEndAluguel.Application.Comum.Excecoes;
using BackEndAluguel.Application.Inquilinos.Comandos;
using BackEndAluguel.Application.Inquilinos.Manipuladores;
using BackEndAluguel.Domain.Entidades;
using BackEndAluguel.Domain.Interfaces;
using FluentAssertions;
using Moq;

namespace BackEndAluguel.Tests.Aplicacao;

/// <summary>
/// Testes unitários para os manipuladores CQRS de Inquilino.
/// Usa Moq para simular os repositórios e validar o comportamento dos handlers.
/// </summary>
public class InquilinoManipuladorTestes
{
    private readonly Mock<IInquilinoRepositorio> _inquilinoRepositorioMock;
    private readonly Mock<IApartamentoRepositorio> _apartamentoRepositorioMock;

    private static readonly Guid ApartamentoId = Guid.NewGuid();
    private static readonly DateOnly DataEntrada = new(2024, 1, 1);
    private static readonly DateOnly DataVencimento = new(2026, 12, 31);
    private static readonly DateOnly DataNascimento = new(1990, 5, 15);

    /// <summary>
    /// Inicializa os mocks antes de cada teste.
    /// </summary>
    public InquilinoManipuladorTestes()
    {
        _inquilinoRepositorioMock = new Mock<IInquilinoRepositorio>();
        _apartamentoRepositorioMock = new Mock<IApartamentoRepositorio>();
    }

    // =====================================================
    // Testes de CriarInquilinoManipulador
    // =====================================================

    /// <summary>
    /// Verifica que criar inquilino com dados válidos retorna DTO e marca o apartamento como ocupado.
    /// </summary>
    [Fact]
    public async Task CriarInquilino_DadosValidos_DeveCriarVincularApartamentoERetornarDto()
    {
        // Arrange
        var apartamento = new Apartamento("101", "A");

        _inquilinoRepositorioMock.Setup(r => r.ExistePorCpfAsync("12345678901", It.IsAny<CancellationToken>()))
            .ReturnsAsync(false);
        _apartamentoRepositorioMock.Setup(r => r.ObterPorIdAsync(ApartamentoId, It.IsAny<CancellationToken>()))
            .ReturnsAsync(apartamento);
        _inquilinoRepositorioMock.Setup(r => r.AdicionarAsync(It.IsAny<Inquilino>(), It.IsAny<CancellationToken>()))
            .Returns(Task.CompletedTask);
        _inquilinoRepositorioMock.Setup(r => r.SalvarAlteracoesAsync(It.IsAny<CancellationToken>()))
            .ReturnsAsync(1);

        var manipulador = new CriarInquilinoManipulador(_inquilinoRepositorioMock.Object, _apartamentoRepositorioMock.Object);
        var comando = new CriarInquilinoComando("João da Silva", "12345678901", DataNascimento, "12345678", "SSP-SP", "11999990000", Domain.Enumeradores.EstadoCivil.Solteiro, 2, DataEntrada, DataVencimento, 1500m, ApartamentoId);

        // Act
        var resultado = await manipulador.Handle(comando, CancellationToken.None);

        // Assert
        resultado.Should().NotBeNull();
        resultado.NomeCompleto.Should().Be("João da Silva");
        resultado.Cpf.Should().Be("12345678901");
        resultado.ValorAluguel.Should().Be(1500m);
        resultado.ApartamentoId.Should().Be(ApartamentoId);

        // Deve ter marcado o apartamento como ocupado
        apartamento.Ocupado.Should().BeTrue();
        _apartamentoRepositorioMock.Verify(r => r.Atualizar(apartamento), Times.Once);
    }

    /// <summary>
    /// Verifica que tentar cadastrar inquilino com CPF duplicado lança RegraDeNegocioExcecao.
    /// </summary>
    [Fact]
    public async Task CriarInquilino_CpfJaCadastrado_DeveLancarRegraDeNegocioExcecao()
    {
        // Arrange
        _inquilinoRepositorioMock.Setup(r => r.ExistePorCpfAsync("12345678901", It.IsAny<CancellationToken>()))
            .ReturnsAsync(true);

        var manipulador = new CriarInquilinoManipulador(_inquilinoRepositorioMock.Object, _apartamentoRepositorioMock.Object);
        var comando = new CriarInquilinoComando("João", "12345678901", DataNascimento, "12345678", "SSP-SP", "11999990000", Domain.Enumeradores.EstadoCivil.Solteiro, 1, DataEntrada, DataVencimento, 1000m, ApartamentoId);

        // Act
        var acao = async () => await manipulador.Handle(comando, CancellationToken.None);

        // Assert
        await acao.Should().ThrowAsync<RegraDeNegocioExcecao>()
            .WithMessage("*CPF*");

        _inquilinoRepositorioMock.Verify(r => r.AdicionarAsync(It.IsAny<Inquilino>(), It.IsAny<CancellationToken>()), Times.Never);
    }

    /// <summary>
    /// Verifica que tentar criar inquilino com apartamento inexistente lança EntidadeNaoEncontradaExcecao.
    /// </summary>
    [Fact]
    public async Task CriarInquilino_ApartamentoNaoEncontrado_DeveLancarEntidadeNaoEncontradaExcecao()
    {
        // Arrange
        _inquilinoRepositorioMock.Setup(r => r.ExistePorCpfAsync(It.IsAny<string>(), It.IsAny<CancellationToken>()))
            .ReturnsAsync(false);
        _apartamentoRepositorioMock.Setup(r => r.ObterPorIdAsync(It.IsAny<Guid>(), It.IsAny<CancellationToken>()))
            .ReturnsAsync((Apartamento?)null);

        var manipulador = new CriarInquilinoManipulador(_inquilinoRepositorioMock.Object, _apartamentoRepositorioMock.Object);
        var comando = new CriarInquilinoComando("João", "12345678901", DataNascimento, "12345678", "SSP-SP", "11999990000", Domain.Enumeradores.EstadoCivil.Solteiro, 1, DataEntrada, DataVencimento, 1000m, Guid.NewGuid());

        // Act
        var acao = async () => await manipulador.Handle(comando, CancellationToken.None);

        // Assert
        await acao.Should().ThrowAsync<EntidadeNaoEncontradaExcecao>();
    }

    // =====================================================
    // Testes de RemoverInquilinoManipulador
    // =====================================================

    /// <summary>
    /// Verifica que remover inquilino existente libera o apartamento.
    /// </summary>
    [Fact]
    public async Task RemoverInquilino_InquilinoExistente_DeveRemoverELiberarApartamento()
    {
        // Arrange
        var apartamento = new Apartamento("101", "A");
        apartamento.MarcarComoOcupado();

        var inquilino = new Inquilino("João", "12345678901", 1, DataEntrada, DataVencimento, 1000m, apartamento.Id);

        _inquilinoRepositorioMock.Setup(r => r.ObterPorIdAsync(inquilino.Id, It.IsAny<CancellationToken>()))
            .ReturnsAsync(inquilino);
        _apartamentoRepositorioMock.Setup(r => r.ObterPorIdAsync(inquilino.ApartamentoId, It.IsAny<CancellationToken>()))
            .ReturnsAsync(apartamento);
        _inquilinoRepositorioMock.Setup(r => r.SalvarAlteracoesAsync(It.IsAny<CancellationToken>()))
            .ReturnsAsync(1);

        var manipulador = new RemoverInquilinoManipulador(_inquilinoRepositorioMock.Object, _apartamentoRepositorioMock.Object);
        var comando = new RemoverInquilinoComando(inquilino.Id);

        // Act
        var resultado = await manipulador.Handle(comando, CancellationToken.None);

        // Assert
        resultado.Should().BeTrue();
        apartamento.Ocupado.Should().BeFalse();
        _inquilinoRepositorioMock.Verify(r => r.Remover(inquilino), Times.Once);
        _apartamentoRepositorioMock.Verify(r => r.Atualizar(apartamento), Times.Once);
    }

    // =====================================================
    // Testes de AtualizarInquilinoManipulador
    // =====================================================

    /// <summary>
    /// Verifica que atualizar inquilino existente aplica e persiste as alterações.
    /// </summary>
    [Fact]
    public async Task AtualizarInquilino_InquilinoExistente_DeveAtualizarERetornarDto()
    {
        // Arrange
        var inquilino = new Inquilino("João", "12345678901", 1, DataEntrada, DataVencimento, 1000m, ApartamentoId);

        _inquilinoRepositorioMock.Setup(r => r.ObterPorIdAsync(inquilino.Id, It.IsAny<CancellationToken>()))
            .ReturnsAsync(inquilino);
        _inquilinoRepositorioMock.Setup(r => r.SalvarAlteracoesAsync(It.IsAny<CancellationToken>()))
            .ReturnsAsync(1);

        var manipulador = new AtualizarInquilinoManipulador(_inquilinoRepositorioMock.Object);
        var comando = new AtualizarInquilinoComando(inquilino.Id, "Pedro Santos", 3, new DateOnly(2027, 6, 30), 1800m, "87654321", "SSP-RJ", "21988887777", Domain.Enumeradores.EstadoCivil.Casado);

        // Act
        var resultado = await manipulador.Handle(comando, CancellationToken.None);

        // Assert
        resultado.NomeCompleto.Should().Be("Pedro Santos");
        resultado.QuantidadeMoradores.Should().Be(3);
        resultado.ValorAluguel.Should().Be(1800m);
        _inquilinoRepositorioMock.Verify(r => r.Atualizar(inquilino), Times.Once);
    }
}

using BackEndAluguel.Domain.Entidades;
using FluentAssertions;

namespace BackEndAluguel.Tests.Dominio;

/// <summary>
/// Testes unitários para a entidade <see cref="Inquilino"/>.
/// Valida criação, validações e regras de negócio do inquilino.
/// </summary>
public class InquilinoTestes
{
    // Dados auxiliares reutilizáveis nos testes
    private static readonly Guid ApartamentoId = Guid.NewGuid();
    private static readonly DateOnly DataEntrada = new(2024, 1, 1);
    private static readonly DateOnly DataVencimento = new(2025, 12, 31);

    /// <summary>
    /// Cria um inquilino válido para ser usado nos testes.
    /// </summary>
    private static Inquilino CriarInquilinoValido()
        => new("João da Silva", "12345678901", 2, DataEntrada, DataVencimento, 1500.00m, ApartamentoId);

    // =====================================================
    // Testes de criação
    // =====================================================

    /// <summary>
    /// Verifica que um inquilino é criado corretamente com dados válidos.
    /// </summary>
    [Fact]
    public void CriarInquilino_ComDadosValidos_DeveCriarComSucesso()
    {
        // Arrange & Act
        var inquilino = CriarInquilinoValido();

        // Assert
        inquilino.NomeCompleto.Should().Be("João da Silva");
        inquilino.Cpf.Should().Be("12345678901");
        inquilino.QuantidadeMoradores.Should().Be(2);
        inquilino.DataEntrada.Should().Be(DataEntrada);
        inquilino.DataVencimentoContrato.Should().Be(DataVencimento);
        inquilino.ValorAluguel.Should().Be(1500.00m);
        inquilino.ApartamentoId.Should().Be(ApartamentoId);
        inquilino.DiasAlertaVencimento.Should().Equal(new List<int> { 30, 60, 90 });
    }

    /// <summary>
    /// Verifica que o CPF com formatação é limpo para somente dígitos.
    /// </summary>
    [Fact]
    public void CriarInquilino_CpfComFormatacao_DeveLimparParaSomentedigitos()
    {
        // Arrange & Act
        var inquilino = new Inquilino("Maria", "123.456.789-01", 1, DataEntrada, DataVencimento, 1000m, ApartamentoId);

        // Assert
        inquilino.Cpf.Should().Be("12345678901");
    }

    /// <summary>
    /// Verifica que alertas personalizados são respeitados.
    /// </summary>
    [Fact]
    public void CriarInquilino_ComAlertasPersonalizados_DeveUsarAlertasInformados()
    {
        // Arrange
        var alertas = new List<int> { 15, 45 };

        // Act
        var inquilino = new Inquilino("Maria", "12345678901", 1, DataEntrada, DataVencimento, 1000m, ApartamentoId, alertas);

        // Assert
        inquilino.DiasAlertaVencimento.Should().Equal(alertas);
    }

    // =====================================================
    // Testes de validação
    // =====================================================

    /// <summary>
    /// Verifica que nome vazio lança exceção.
    /// </summary>
    [Theory]
    [InlineData("")]
    [InlineData("   ")]
    public void CriarInquilino_ComNomeVazio_DeveLancarExcecao(string nome)
    {
        var acao = () => new Inquilino(nome, "12345678901", 1, DataEntrada, DataVencimento, 1000m, ApartamentoId);
        acao.Should().Throw<ArgumentException>().WithMessage("*nome*");
    }

    /// <summary>
    /// Verifica que CPF com menos de 11 dígitos lança exceção.
    /// </summary>
    [Theory]
    [InlineData("1234")]
    [InlineData("123456789012")]
    public void CriarInquilino_ComCpfInvalido_DeveLancarExcecao(string cpf)
    {
        var acao = () => new Inquilino("João", cpf, 1, DataEntrada, DataVencimento, 1000m, ApartamentoId);
        acao.Should().Throw<ArgumentException>().WithMessage("*CPF*");
    }

    /// <summary>
    /// Verifica que quantidade de moradores zero lança exceção.
    /// </summary>
    [Theory]
    [InlineData(0)]
    [InlineData(-1)]
    public void CriarInquilino_ComQuantidadeMoradoresInvalida_DeveLancarExcecao(int quantidade)
    {
        var acao = () => new Inquilino("João", "12345678901", quantidade, DataEntrada, DataVencimento, 1000m, ApartamentoId);
        acao.Should().Throw<ArgumentException>().WithMessage("*moradores*");
    }

    /// <summary>
    /// Verifica que valor de aluguel zero ou negativo lança exceção.
    /// </summary>
    [Theory]
    [InlineData(0)]
    [InlineData(-100)]
    public void CriarInquilino_ComValorAluguelInvalido_DeveLancarExcecao(decimal valor)
    {
        var acao = () => new Inquilino("João", "12345678901", 1, DataEntrada, DataVencimento, valor, ApartamentoId);
        acao.Should().Throw<ArgumentException>().WithMessage("*aluguel*");
    }

    /// <summary>
    /// Verifica que data de entrada posterior ao vencimento lança exceção.
    /// </summary>
    [Fact]
    public void CriarInquilino_DataEntradaPosteriorAoVencimento_DeveLancarExcecao()
    {
        var acao = () => new Inquilino("João", "12345678901", 1,
            new DateOnly(2025, 12, 31), new DateOnly(2024, 1, 1), 1000m, ApartamentoId);

        acao.Should().Throw<ArgumentException>().WithMessage("*data de entrada*");
    }

    // =====================================================
    // Testes de alertas de vencimento
    // =====================================================

    /// <summary>
    /// Verifica que ContratoVenceEm retorna verdadeiro quando dentro do prazo.
    /// </summary>
    [Fact]
    public void ContratoVenceEm_ContratoDentroDosPrazo_DeveRetornarVerdadeiro()
    {
        // Arrange — vence daqui a 20 dias
        var vencimento = DateOnly.FromDateTime(DateTime.Today.AddDays(20));
        var inquilino = new Inquilino("João", "12345678901", 1,
            DateOnly.FromDateTime(DateTime.Today.AddDays(-30)), vencimento, 1000m, ApartamentoId);

        // Act & Assert
        inquilino.ContratoVenceEm(30).Should().BeTrue();
        inquilino.ContratoVenceEm(10).Should().BeFalse();
    }

    // =====================================================
    // Testes de atualização
    // =====================================================

    /// <summary>
    /// Verifica que a atualização aplica os novos dados corretamente.
    /// </summary>
    [Fact]
    public void Atualizar_ComDadosValidos_DeveAtualizarPropriedades()
    {
        // Arrange
        var inquilino = CriarInquilinoValido();

        // Act
        inquilino.Atualizar("Pedro dos Santos", 3, new DateOnly(2026, 6, 30), 1800m, new List<int> { 15, 30 });

        // Assert
        inquilino.NomeCompleto.Should().Be("Pedro dos Santos");
        inquilino.QuantidadeMoradores.Should().Be(3);
        inquilino.ValorAluguel.Should().Be(1800m);
        inquilino.DiasAlertaVencimento.Should().Equal(new List<int> { 15, 30 });
        inquilino.AtualizadoEm.Should().NotBeNull();
    }
}

