    {
        _contexto.Dispose();
        GC.SuppressFinalize(this);
    }
}

using BackEndAluguel.Api.Modelos;
using BackEndAluguel.Application.Auth.Comandos;
using BackEndAluguel.Application.Auth.DTOs;
using MediatR;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;

namespace BackEndAluguel.Api.Controllers;

/// <summary>
/// Controller responsavel pela autenticacao e registro de usuarios na plataforma GestAluguel.
/// Oferece endpoints para registro do host, login do host e login dos inquilinos.
/// </summary>
[ApiController]
[Route("api/[controller]")]
[Produces("application/json")]
[AllowAnonymous]
public class AuthController : ControllerBase
{
    private readonly IMediator _mediator;

    /// <summary>Inicializa o controller com o mediator injetado.</summary>
    public AuthController(IMediator mediator) => _mediator = mediator;

    /// <summary>
    /// Registra um novo host/locador na plataforma.
    /// Cria a conta com e-mail pendente de confirmação e envia o link de ativação por e-mail.
    /// </summary>
    /// <param name="corpo">Dados do novo host: nome, CPF, data de nascimento, e-mail e senha.</param>
    /// <response code="201">Host registrado com sucesso. Aguarda confirmação por e-mail.</response>
    /// <response code="400">Dados inválidos, CPF ou e-mail já cadastrado, senha muito curta.</response>
    [HttpPost("registrar")]
    [ProducesResponseType(typeof(RespostaApi<HostDto>), StatusCodes.Status201Created)]
    [ProducesResponseType(typeof(RespostaErro), StatusCodes.Status400BadRequest)]
    public async Task<IActionResult> RegistrarHost([FromBody] RegistrarHostCorpo corpo, CancellationToken cancellationToken)
    {
        var resultado = await _mediator.Send(
            new RegistrarHostComando(corpo.NomeCompleto, corpo.Cpf, corpo.DataNascimento, corpo.Email, corpo.Senha),
            cancellationToken);

        return StatusCode(StatusCodes.Status201Created,
            RespostaApi<HostDto>.Ok(resultado, "Conta criada! Verifique seu e-mail para confirmar o cadastro."));
    }

    /// <summary>
    /// Confirma o e-mail do host a partir do token recebido no e-mail de confirmação.
    /// O frontend deve chamar este endpoint ao exibir a página de confirmação.
    /// </summary>
    /// <param name="corpo">Token de confirmação.</param>
    /// <response code="200">E-mail confirmado. Conta ativa.</response>
    /// <response code="400">Token inválido, já utilizado ou expirado.</response>
    [HttpPost("confirmar-email")]
    [ProducesResponseType(typeof(RespostaApi<bool>), StatusCodes.Status200OK)]
    [ProducesResponseType(typeof(RespostaErro), StatusCodes.Status400BadRequest)]
    public async Task<IActionResult> ConfirmarEmail([FromBody] ConfirmarEmailCorpo corpo, CancellationToken cancellationToken)
    {
        var resultado = await _mediator.Send(new ConfirmarEmailHostComando(corpo.Token), cancellationToken);
        return Ok(RespostaApi<bool>.Ok(resultado, "E-mail confirmado com sucesso! Agora você pode fazer login."));
    }

    /// <summary>
    /// Autentica o administrador (host/locador) pelo e-mail e senha.
    /// Retorna um token JWT com perfil "Host" valido pelo tempo configurado.
    /// </summary>
    /// <param name="corpo">E-mail e senha do host.</param>
    /// <response code="200">Login realizado. Token JWT retornado.</response>
    /// <response code="400">Credenciais inválidas ou conta não confirmada.</response>
    [HttpPost("host")]
    [ProducesResponseType(typeof(RespostaApi<TokenResultadoDto>), StatusCodes.Status200OK)]
    [ProducesResponseType(typeof(RespostaErro), StatusCodes.Status400BadRequest)]
    public async Task<IActionResult> LoginHost([FromBody] LoginHostCorpo corpo, CancellationToken cancellationToken)
    {
        var resultado = await _mediator.Send(new LoginHostComando(corpo.Email, corpo.Senha), cancellationToken);
        return Ok(RespostaApi<TokenResultadoDto>.Ok(resultado, "Login realizado com sucesso."));
    }

    /// <summary>
    /// Autentica um inquilino pelo CPF e data de nascimento.
    /// Retorna um token JWT com perfil "Inquilino" contendo o InquilinoId como claim.
    /// </summary>
    /// <param name="corpo">CPF e data de nascimento do inquilino.</param>
    /// <response code="200">Login realizado. Token JWT retornado.</response>
    /// <response code="400">CPF ou data de nascimento incorretos.</response>
    [HttpPost("inquilino")]
    [ProducesResponseType(typeof(RespostaApi<TokenResultadoDto>), StatusCodes.Status200OK)]
    [ProducesResponseType(typeof(RespostaErro), StatusCodes.Status400BadRequest)]
    public async Task<IActionResult> LoginInquilino([FromBody] LoginInquilinoCorpo corpo, CancellationToken cancellationToken)
    {
        var resultado = await _mediator.Send(new LoginInquilinoComando(corpo.Cpf, corpo.DataNascimento), cancellationToken);
        return Ok(RespostaApi<TokenResultadoDto>.Ok(resultado, "Login realizado com sucesso."));
    }
}

// ─── Corpos das requisicoes ───────────────────────────────────────────────────

/// <summary>Corpo da requisicao de registro de host.</summary>
public record RegistrarHostCorpo(
    /// <summary>Nome completo do host.</summary>
    string NomeCompleto,
    /// <summary>CPF do host (com ou sem formatação).</summary>
    string Cpf,
    /// <summary>Data de nascimento do host.</summary>
    DateOnly DataNascimento,
    /// <summary>E-mail do host. Será utilizado como login.</summary>
    string Email,
    /// <summary>Senha (mínimo 6 caracteres). Será criptografada antes de armazenar.</summary>
    string Senha
);

/// <summary>Corpo da requisicao de confirmacao de e-mail.</summary>
public record ConfirmarEmailCorpo(
    /// <summary>Token de confirmação recebido por e-mail.</summary>
    string Token
);

/// <summary>Corpo da requisicao de login do host.</summary>
public record LoginHostCorpo(
    /// <summary>E-mail cadastrado do host.</summary>
    string Email,
    /// <summary>Senha do host.</summary>
    string Senha
);

/// <summary>Corpo da requisicao de login do inquilino.</summary>
public record LoginInquilinoCorpo(
    /// <summary>CPF do inquilino (com ou sem formatacao).</summary>
    string Cpf,
    /// <summary>Data de nascimento do inquilino (segundo fator de autenticacao).</summary>
    DateOnly DataNascimento
);

using BackEndAluguel.Api.Modelos;
using BackEndAluguel.Application.Contratos.Comandos;
using BackEndAluguel.Application.Contratos.Consultas;
using BackEndAluguel.Application.Contratos.DTOs;
using MediatR;
using Microsoft.AspNetCore.Mvc;

namespace BackEndAluguel.Api.Controllers;

/// <summary>
/// Controller responsavel pelo gerenciamento de contratos assinados dos inquilinos.
/// Permite o upload de arquivos PDF ou imagem e a consulta dos contratos existentes.
/// </summary>
[ApiController]
[Route("api/[controller]")]
[Produces("application/json")]
public class ContratosController : ControllerBase
{
    private readonly IMediator _mediator;
    private readonly IConfiguration _configuration;

    /// <summary>Inicializa o controller com mediator e configuracao.</summary>
    public ContratosController(IMediator mediator, IConfiguration configuration)
    {
        _mediator = mediator;
        _configuration = configuration;
    }

    /// <summary>Lista todos os contratos de um inquilino.</summary>
    [HttpGet("inquilino/{inquilinoId:guid}")]
    [ProducesResponseType(typeof(RespostaApi<IEnumerable<ContratoInquilinoDto>>), StatusCodes.Status200OK)]
    public async Task<IActionResult> ListarPorInquilino(Guid inquilinoId, CancellationToken cancellationToken)
    {
        var resultado = await _mediator.Send(new ListarContratosPorInquilinoConsulta(inquilinoId), cancellationToken);
        return Ok(RespostaApi<IEnumerable<ContratoInquilinoDto>>.Ok(resultado));
    }

    /// <summary>Busca um contrato pelo ID.</summary>
    [HttpGet("{id:guid}")]
    [ProducesResponseType(typeof(RespostaApi<ContratoInquilinoDto>), StatusCodes.Status200OK)]
    [ProducesResponseType(typeof(RespostaErro), StatusCodes.Status404NotFound)]
    public async Task<IActionResult> ObterPorId(Guid id, CancellationToken cancellationToken)
    {
        var resultado = await _mediator.Send(new ObterContratoPorIdConsulta(id), cancellationToken);
        if (resultado is null)
            return NotFound(RespostaErro.Criar($"Contrato com id '{id}' nao encontrado."));
        return Ok(RespostaApi<ContratoInquilinoDto>.Ok(resultado));
    }

    /// <summary>
    /// Faz o upload de um contrato (PDF ou imagem) e registra os metadados no banco.
    /// Tipos permitidos: application/pdf, image/jpeg, image/png.
    /// Tamanho maximo: 10 MB.
    /// </summary>
    [HttpPost("inquilino/{inquilinoId:guid}/upload")]
    [ProducesResponseType(typeof(RespostaApi<ContratoInquilinoDto>), StatusCodes.Status201Created)]
    [ProducesResponseType(typeof(RespostaErro), StatusCodes.Status400BadRequest)]
    [RequestSizeLimit(10 * 1024 * 1024)] // Limite de 10 MB
    public async Task<IActionResult> Upload(
        Guid inquilinoId,
        IFormFile arquivo,
        [FromForm] string? descricao,
        CancellationToken cancellationToken)
    {
        // Valida o tipo MIME permitido
        var tiposPermitidos = new[] { "application/pdf", "image/jpeg", "image/png", "image/jpg" };
        if (!tiposPermitidos.Contains(arquivo.ContentType.ToLower()))
            return BadRequest(RespostaErro.Criar("Tipo de arquivo nao permitido. Envie um PDF ou imagem (JPEG, PNG)."));

        if (arquivo.Length == 0)
            return BadRequest(RespostaErro.Criar("O arquivo nao pode estar vazio."));

        // Determina a pasta de armazenamento a partir da configuracao
        var pastaRaiz = _configuration["Contratos:PastaArmazenamento"] ?? "wwwroot/contratos";
        var pastaInquilino = Path.Combine(pastaRaiz, inquilinoId.ToString());
        Directory.CreateDirectory(pastaInquilino);

        // Gera um nome unico para o arquivo (evita colisoes)
        var extensao = Path.GetExtension(arquivo.FileName);
        var nomeArquivoSalvo = $"{Guid.NewGuid()}{extensao}";
        var caminhoRelativo = Path.Combine(inquilinoId.ToString(), nomeArquivoSalvo);
        var caminhoCompleto = Path.Combine(pastaRaiz, caminhoRelativo);

        // Salva o arquivo no disco
        await using (var stream = new FileStream(caminhoCompleto, FileMode.Create))
            await arquivo.CopyToAsync(stream, cancellationToken);

        // Registra os metadados no banco via comando CQRS
        var comando = new RegistrarContratoComando(
            inquilinoId,
            arquivo.FileName,
            caminhoRelativo,
            arquivo.ContentType,
            arquivo.Length,
            descricao);

        var resultado = await _mediator.Send(comando, cancellationToken);
        return CreatedAtAction(nameof(ObterPorId), new { id = resultado.Id },
            RespostaApi<ContratoInquilinoDto>.Ok(resultado, "Contrato enviado com sucesso."));
    }

    /// <summary>
    /// Faz o download do arquivo de contrato pelo ID.
    /// </summary>
    [HttpGet("{id:guid}/download")]
    [ProducesResponseType(StatusCodes.Status200OK)]
    [ProducesResponseType(typeof(RespostaErro), StatusCodes.Status404NotFound)]
    public async Task<IActionResult> Download(Guid id, CancellationToken cancellationToken)
    {
        var contrato = await _mediator.Send(new ObterContratoPorIdConsulta(id), cancellationToken);
        if (contrato is null)
            return NotFound(RespostaErro.Criar($"Contrato com id '{id}' nao encontrado."));

        // Reconstroi o caminho completo a partir do caminho relativo armazenado
        var pastaRaiz = _configuration["Contratos:PastaArmazenamento"] ?? "wwwroot/contratos";
        var caminhoCompleto = Path.Combine(pastaRaiz, contrato.NomeOriginalArquivo);

        // Tenta encontrar o arquivo pelo caminho relativo persistido
        // (a API guarda caminhoArquivo no DTO, mas aqui temos apenas NomeOriginalArquivo)
        // Precisamos buscar a entidade real — vamos usar a consulta adequada
        if (!System.IO.File.Exists(caminhoCompleto))
            return NotFound(RespostaErro.Criar("Arquivo fisico nao encontrado no servidor."));

        var bytes = await System.IO.File.ReadAllBytesAsync(caminhoCompleto, cancellationToken);
        return File(bytes, contrato.TipoConteudo, contrato.NomeOriginalArquivo);
    }

    /// <summary>Atualiza a descricao de um contrato existente.</summary>
    [HttpPatch("{id:guid}/descricao")]
    [ProducesResponseType(typeof(RespostaApi<ContratoInquilinoDto>), StatusCodes.Status200OK)]
    [ProducesResponseType(typeof(RespostaErro), StatusCodes.Status404NotFound)]
    public async Task<IActionResult> AtualizarDescricao(Guid id, [FromBody] AtualizarDescricaoContratoCorpo corpo, CancellationToken cancellationToken)
    {
        var resultado = await _mediator.Send(new AtualizarDescricaoContratoComando(id, corpo.Descricao), cancellationToken);
        return Ok(RespostaApi<ContratoInquilinoDto>.Ok(resultado, "Descricao atualizada com sucesso."));
    }

    /// <summary>Remove um contrato e o arquivo fisico do servidor.</summary>
    [HttpDelete("{id:guid}")]
    [ProducesResponseType(StatusCodes.Status204NoContent)]
    [ProducesResponseType(typeof(RespostaErro), StatusCodes.Status404NotFound)]
    public async Task<IActionResult> Remover(Guid id, CancellationToken cancellationToken)
    {
        await _mediator.Send(new RemoverContratoComando(id), cancellationToken);
        return NoContent();
    }
}

/// <summary>Corpo para atualizacao da descricao do contrato.</summary>
public record AtualizarDescricaoContratoCorpo(string? Descricao);

using BackEndAluguel.Api.Modelos;
using BackEndAluguel.Application.Contratos.Comandos;
using BackEndAluguel.Application.Contratos.Consultas;
using BackEndAluguel.Application.Contratos.DTOs;
using MediatR;
using Microsoft.AspNetCore.Mvc;

namespace BackEndAluguel.Api.Controllers;

/// <summary>
/// Controller responsavel pelo gerenciamento de contratos assinados dos inquilinos.
/// Permite o upload de arquivos PDF ou imagem e a consulta dos contratos existentes.
/// </summary>
[ApiController]
[Route("api/[controller]")]
[Produces("application/json")]
public class ContratosController : ControllerBase
{
    private readonly IMediator _mediator;
    private readonly IConfiguration _configuration;

    /// <summary>Inicializa o controller com mediator e configuracao.</summary>
    public ContratosController(IMediator mediator, IConfiguration configuration)
    {
        _mediator = mediator;
        _configuration = configuration;
    }

    /// <summary>Lista todos os contratos de um inquilino.</summary>
    [HttpGet("inquilino/{inquilinoId:guid}")]
    [ProducesResponseType(typeof(RespostaApi<IEnumerable<ContratoInquilinoDto>>), StatusCodes.Status200OK)]
    public async Task<IActionResult> ListarPorInquilino(Guid inquilinoId, CancellationToken cancellationToken)
    {
        var resultado = await _mediator.Send(new ListarContratosPorInquilinoConsulta(inquilinoId), cancellationToken);
        return Ok(RespostaApi<IEnumerable<ContratoInquilinoDto>>.Ok(resultado));
    }

    /// <summary>Busca um contrato pelo ID.</summary>
    [HttpGet("{id:guid}")]
    [ProducesResponseType(typeof(RespostaApi<ContratoInquilinoDto>), StatusCodes.Status200OK)]
    [ProducesResponseType(typeof(RespostaErro), StatusCodes.Status404NotFound)]
    public async Task<IActionResult> ObterPorId(Guid id, CancellationToken cancellationToken)
    {
        var resultado = await _mediator.Send(new ObterContratoPorIdConsulta(id), cancellationToken);
        if (resultado is null)
            return NotFound(RespostaErro.Criar($"Contrato com id '{id}' nao encontrado."));
        return Ok(RespostaApi<ContratoInquilinoDto>.Ok(resultado));
    }

    /// <summary>
    /// Faz o upload de um contrato (PDF ou imagem) e registra os metadados no banco.
    /// Tipos permitidos: application/pdf, image/jpeg, image/png.
    /// Tamanho maximo: 10 MB.
    /// </summary>
    [HttpPost("inquilino/{inquilinoId:guid}/upload")]
    [ProducesResponseType(typeof(RespostaApi<ContratoInquilinoDto>), StatusCodes.Status201Created)]
    [ProducesResponseType(typeof(RespostaErro), StatusCodes.Status400BadRequest)]
    [RequestSizeLimit(10 * 1024 * 1024)] // Limite de 10 MB
    public async Task<IActionResult> Upload(
        Guid inquilinoId,
        IFormFile arquivo,
        [FromForm] string? descricao,
        CancellationToken cancellationToken)
    {
        // Valida o tipo MIME permitido
        var tiposPermitidos = new[] { "application/pdf", "image/jpeg", "image/png", "image/jpg" };
        if (!tiposPermitidos.Contains(arquivo.ContentType.ToLower()))
            return BadRequest(RespostaErro.Criar("Tipo de arquivo nao permitido. Envie um PDF ou imagem (JPEG, PNG)."));

        if (arquivo.Length == 0)
            return BadRequest(RespostaErro.Criar("O arquivo nao pode estar vazio."));

        // Determina a pasta de armazenamento a partir da configuracao
        var pastaRaiz = _configuration["Contratos:PastaArmazenamento"] ?? "wwwroot/contratos";
        var pastaInquilino = Path.Combine(pastaRaiz, inquilinoId.ToString());
        Directory.CreateDirectory(pastaInquilino);

        // Gera um nome unico para o arquivo (evita colisoes)
        var extensao = Path.GetExtension(arquivo.FileName);
        var nomeArquivoSalvo = $"{Guid.NewGuid()}{extensao}";
        var caminhoRelativo = Path.Combine(inquilinoId.ToString(), nomeArquivoSalvo);
        var caminhoCompleto = Path.Combine(pastaRaiz, caminhoRelativo);

        // Salva o arquivo no disco
        await using (var stream = new FileStream(caminhoCompleto, FileMode.Create))
            await arquivo.CopyToAsync(stream, cancellationToken);

        // Registra os metadados no banco via comando CQRS
        var comando = new RegistrarContratoComando(
            inquilinoId,
            arquivo.FileName,
            caminhoRelativo,
            arquivo.ContentType,
            arquivo.Length,
            descricao);

        var resultado = await _mediator.Send(comando, cancellationToken);
        return CreatedAtAction(nameof(ObterPorId), new { id = resultado.Id },
            RespostaApi<ContratoInquilinoDto>.Ok(resultado, "Contrato enviado com sucesso."));
    }

    /// <summary>
    /// Faz o download do arquivo de contrato pelo ID.
    /// </summary>
    [HttpGet("{id:guid}/download")]
    [ProducesResponseType(StatusCodes.Status200OK)]
    [ProducesResponseType(typeof(RespostaErro), StatusCodes.Status404NotFound)]
    public async Task<IActionResult> Download(Guid id, CancellationToken cancellationToken)
    {
        var contrato = await _mediator.Send(new ObterContratoPorIdConsulta(id), cancellationToken);
        if (contrato is null)
            return NotFound(RespostaErro.Criar($"Contrato com id '{id}' nao encontrado."));

        // Reconstroi o caminho completo a partir do caminho relativo persistido
        var pastaRaiz = _configuration["Contratos:PastaArmazenamento"] ?? "wwwroot/contratos";
        var caminhoCompleto = Path.Combine(pastaRaiz, contrato.CaminhoArquivo);

        if (!System.IO.File.Exists(caminhoCompleto))
            return NotFound(RespostaErro.Criar("Arquivo fisico nao encontrado no servidor."));

        var bytes = await System.IO.File.ReadAllBytesAsync(caminhoCompleto, cancellationToken);
        return File(bytes, contrato.TipoConteudo, contrato.NomeOriginalArquivo);
    }

    /// <summary>Atualiza a descricao de um contrato existente.</summary>
    [HttpPatch("{id:guid}/descricao")]
    [ProducesResponseType(typeof(RespostaApi<ContratoInquilinoDto>), StatusCodes.Status200OK)]
    [ProducesResponseType(typeof(RespostaErro), StatusCodes.Status404NotFound)]
    public async Task<IActionResult> AtualizarDescricao(Guid id, [FromBody] AtualizarDescricaoContratoCorpo corpo, CancellationToken cancellationToken)
    {
        var resultado = await _mediator.Send(new AtualizarDescricaoContratoComando(id, corpo.Descricao), cancellationToken);
        return Ok(RespostaApi<ContratoInquilinoDto>.Ok(resultado, "Descricao atualizada com sucesso."));
    }

    /// <summary>Remove um contrato e o arquivo fisico do servidor.</summary>
    [HttpDelete("{id:guid}")]
    [ProducesResponseType(StatusCodes.Status204NoContent)]
    [ProducesResponseType(typeof(RespostaErro), StatusCodes.Status404NotFound)]
    public async Task<IActionResult> Remover(Guid id, CancellationToken cancellationToken)
    {
        await _mediator.Send(new RemoverContratoComando(id), cancellationToken);
        return NoContent();
    }
}

/// <summary>Corpo para atualizacao da descricao do contrato.</summary>
public record AtualizarDescricaoContratoCorpo(string? Descricao);

using BackEndAluguel.Api.Modelos;
using BackEndAluguel.Application.Faturas.Comandos;
using BackEndAluguel.Application.Faturas.Consultas;
using BackEndAluguel.Application.Faturas.DTOs;
using BackEndAluguel.Application.Pagamentos.DTOs;
using BackEndAluguel.Domain.Enumeradores;
using MediatR;
using Microsoft.AspNetCore.Mvc;

namespace BackEndAluguel.Api.Controllers;

/// <summary>
/// Controller responsável pelos endpoints de gerenciamento de faturas mensais.
/// Delega toda a lógica aos manipuladores CQRS via MediatR.
/// </summary>
[ApiController]
[Route("api/[controller]")]
[Produces("application/json")]
public class FaturasController : ControllerBase
{
    private readonly IMediator _mediator;

    /// <summary>
    /// Inicializa o controller com o mediator injetado.
    /// </summary>
    public FaturasController(IMediator mediator)
    {
        _mediator = mediator;
    }

    /// <summary>
    /// Busca uma fatura específica pelo seu identificador único.
    /// </summary>
    /// <param name="id">Identificador único (Guid) da fatura.</param>
    /// <response code="200">Fatura encontrada.</response>
    /// <response code="404">Fatura não encontrada.</response>
    [HttpGet("{id:guid}")]
    [ProducesResponseType(typeof(RespostaApi<FaturaDto>), StatusCodes.Status200OK)]
    [ProducesResponseType(typeof(RespostaErro), StatusCodes.Status404NotFound)]
    public async Task<IActionResult> ObterPorId(Guid id, CancellationToken cancellationToken)
    {
        var resultado = await _mediator.Send(new ObterFaturaPorIdConsulta(id), cancellationToken);

        if (resultado is null)
            return NotFound(RespostaErro.Criar($"Fatura com id '{id}' não encontrada."));

        return Ok(RespostaApi<FaturaDto>.Ok(resultado));
    }

    /// <summary>
    /// Retorna todas as faturas de um inquilino específico.
    /// </summary>
    /// <param name="inquilinoId">Identificador do inquilino.</param>
    /// <response code="200">Lista de faturas do inquilino.</response>
    [HttpGet("inquilino/{inquilinoId:guid}")]
    [ProducesResponseType(typeof(RespostaApi<IEnumerable<FaturaDto>>), StatusCodes.Status200OK)]
    public async Task<IActionResult> ObterPorInquilino(Guid inquilinoId, CancellationToken cancellationToken)
    {
        var resultado = await _mediator.Send(new ListarFaturasPorInquilinoConsulta(inquilinoId), cancellationToken);
        return Ok(RespostaApi<IEnumerable<FaturaDto>>.Ok(resultado));
    }

    /// <summary>
    /// Retorna todas as faturas filtradas por status.
    /// Status: 1 = Pendente, 2 = Atrasado, 3 = Pago.
    /// </summary>
    /// <param name="status">Status da fatura (1, 2 ou 3).</param>
    /// <response code="200">Lista de faturas com o status informado.</response>
    /// <response code="400">Status inválido.</response>
    [HttpGet("status/{status:int}")]
    [ProducesResponseType(typeof(RespostaApi<IEnumerable<FaturaDto>>), StatusCodes.Status200OK)]
    [ProducesResponseType(typeof(RespostaErro), StatusCodes.Status400BadRequest)]
    public async Task<IActionResult> ObterPorStatus(int status, CancellationToken cancellationToken)
    {
        if (!Enum.IsDefined(typeof(StatusFatura), status))
            return BadRequest(RespostaErro.Criar($"Status '{status}' inválido. Use: 1=Pendente, 2=Atrasado, 3=Pago."));

        var resultado = await _mediator.Send(new ListarFaturasPorStatusConsulta((StatusFatura)status), cancellationToken);
        return Ok(RespostaApi<IEnumerable<FaturaDto>>.Ok(resultado));
    }

    /// <summary>
    /// Retorna todas as faturas vencidas (data limite ultrapassada e não pagas).
    /// </summary>
    /// <response code="200">Lista de faturas vencidas.</response>
    [HttpGet("vencidas")]
    [ProducesResponseType(typeof(RespostaApi<IEnumerable<FaturaDto>>), StatusCodes.Status200OK)]
    public async Task<IActionResult> ObterVencidas(CancellationToken cancellationToken)
    {
        var resultado = await _mediator.Send(new ListarFaturasVencidasConsulta(), cancellationToken);
        return Ok(RespostaApi<IEnumerable<FaturaDto>>.Ok(resultado));
    }

    /// <summary>
    /// Gera uma nova fatura mensal para um inquilino.
    /// Não é permitido gerar mais de uma fatura por mês de referência para o mesmo inquilino.
    /// </summary>
    /// <param name="comando">Dados da fatura a ser gerada.</param>
    /// <response code="201">Fatura gerada com sucesso.</response>
    /// <response code="400">Fatura duplicada no mês, inquilino não encontrado ou dados inválidos.</response>
    [HttpPost]
    [ProducesResponseType(typeof(RespostaApi<FaturaDto>), StatusCodes.Status201Created)]
    [ProducesResponseType(typeof(RespostaErro), StatusCodes.Status400BadRequest)]
    public async Task<IActionResult> Criar([FromBody] CriarFaturaComando comando, CancellationToken cancellationToken)
    {
        var resultado = await _mediator.Send(comando, cancellationToken);
        return CreatedAtAction(nameof(ObterPorId), new { id = resultado.Id },
            RespostaApi<FaturaDto>.Ok(resultado, "Fatura gerada com sucesso."));
    }

    /// <summary>
    /// Registra o pagamento de uma fatura, alterando o status para Pago.
    /// Não é possível registrar pagamento em uma fatura já paga.
    /// </summary>
    /// <param name="id">Identificador único da fatura.</param>
    /// <param name="corpo">Data do pagamento realizado.</param>
    /// <response code="200">Pagamento registrado com sucesso.</response>
    /// <response code="404">Fatura não encontrada.</response>
    /// <response code="422">Fatura já está paga.</response>
    [HttpPost("{id:guid}/pagamento")]
    [ProducesResponseType(typeof(RespostaApi<FaturaDto>), StatusCodes.Status200OK)]
    [ProducesResponseType(typeof(RespostaErro), StatusCodes.Status404NotFound)]
    [ProducesResponseType(typeof(RespostaErro), StatusCodes.Status422UnprocessableEntity)]
    public async Task<IActionResult> RegistrarPagamento(Guid id, [FromBody] RegistrarPagamentoCorpo corpo, CancellationToken cancellationToken)
    {
        var resultado = await _mediator.Send(new RegistrarPagamentoComando(id, corpo.DataPagamento), cancellationToken);
        return Ok(RespostaApi<FaturaDto>.Ok(resultado, "Pagamento registrado com sucesso."));
    }

    /// <summary>
    /// Atualiza os valores de água e luz de uma fatura ainda não paga.
    /// </summary>
    /// <param name="id">Identificador único da fatura.</param>
    /// <param name="corpo">Novos valores de água e luz.</param>
    /// <response code="200">Valores atualizados com sucesso.</response>
    /// <response code="404">Fatura não encontrada.</response>
    /// <response code="422">Fatura já está paga.</response>
    [HttpPatch("{id:guid}/consumo")]
    [ProducesResponseType(typeof(RespostaApi<FaturaDto>), StatusCodes.Status200OK)]
    [ProducesResponseType(typeof(RespostaErro), StatusCodes.Status404NotFound)]
    [ProducesResponseType(typeof(RespostaErro), StatusCodes.Status422UnprocessableEntity)]
    public async Task<IActionResult> AtualizarConsumo(Guid id, [FromBody] AtualizarConsumoCorpo corpo, CancellationToken cancellationToken)
    {
        var resultado = await _mediator.Send(new AtualizarValoresConsumoComando(id, corpo.ValorAgua, corpo.ValorLuz), cancellationToken);
        return Ok(RespostaApi<FaturaDto>.Ok(resultado, "Valores de consumo atualizados com sucesso."));
    }

    /// <summary>
    /// Atualiza o código ou link do PIX de uma fatura.
    /// </summary>
    /// <param name="id">Identificador único da fatura.</param>
    /// <param name="corpo">Novo código PIX.</param>
    /// <response code="200">Código PIX atualizado com sucesso.</response>
    /// <response code="404">Fatura não encontrada.</response>
    [HttpPatch("{id:guid}/pix")]
    [ProducesResponseType(typeof(RespostaApi<FaturaDto>), StatusCodes.Status200OK)]
    [ProducesResponseType(typeof(RespostaErro), StatusCodes.Status404NotFound)]
    public async Task<IActionResult> AtualizarPix(Guid id, [FromBody] AtualizarPixCorpo corpo, CancellationToken cancellationToken)
    {
        var resultado = await _mediator.Send(new AtualizarCodigoPixComando(id, corpo.CodigoPix), cancellationToken);
        return Ok(RespostaApi<FaturaDto>.Ok(resultado, "Código PIX atualizado com sucesso."));
    }

    /// <summary>
    /// Processa automaticamente todas as faturas vencidas,
    /// alterando o status de Pendente para Atrasado.
    /// Deve ser chamado periodicamente (ex: job diário ou botão no painel).
    /// </summary>
    /// <response code="200">Processamento concluído com a quantidade de faturas atualizadas.</response>
    [HttpPost("processar-vencidas")]
    [ProducesResponseType(typeof(RespostaApi<int>), StatusCodes.Status200OK)]
    public async Task<IActionResult> ProcessarVencidas(CancellationToken cancellationToken)
    {
        var quantidade = await _mediator.Send(new ProcessarFaturasVencidasComando(), cancellationToken);
        return Ok(RespostaApi<int>.Ok(quantidade,
            quantidade == 0
                ? "Nenhuma fatura vencida encontrada."
                : $"{quantidade} fatura(s) marcada(s) como atrasada(s)."));
    }

    /// <summary>
    /// Gera uma cobrança PIX via gateway Asaas para a fatura especificada.
    /// O resultado inclui o código PIX copia-e-cola e a URL do QR Code para exibição ao inquilino.
    /// O CobrancaAsaasId e o CodigoPix são automaticamente salvos na fatura.
    /// Pré-requisito: o WalletId do locador deve estar configurado (POST /api/configuracoes/asaas/subconta).
    /// </summary>
    /// <param name="id">Identificador único da fatura.</param>
    /// <param name="corpo">Percentual de split (opcional).</param>
    /// <response code="200">Cobrança PIX gerada. Retorna código copia-e-cola e QR Code.</response>
    /// <response code="404">Fatura não encontrada.</response>
    /// <response code="422">Fatura já paga ou WalletId não configurado.</response>
    [HttpPost("{id:guid}/gerar-pix")]
    [ProducesResponseType(typeof(RespostaApi<CobrancaPixResultadoDto>), StatusCodes.Status200OK)]
    [ProducesResponseType(typeof(RespostaErro), StatusCodes.Status404NotFound)]
    [ProducesResponseType(typeof(RespostaErro), StatusCodes.Status422UnprocessableEntity)]
    public async Task<IActionResult> GerarPix(Guid id, [FromBody] GerarPixCorpo? corpo, CancellationToken cancellationToken)
    {
        var resultado = await _mediator.Send(new GerarCobrancaPixComando(id, corpo?.PercentualSplit), cancellationToken);
        return Ok(RespostaApi<CobrancaPixResultadoDto>.Ok(resultado, "Cobrança PIX gerada com sucesso."));
    }
}

// ─── Corpos das requisições ──────────────────────────────────────────────────

/// <summary>
/// Corpo da requisição de registro de pagamento.
/// </summary>
public record RegistrarPagamentoCorpo(
    /// <summary>Data em que o pagamento foi efetuado.</summary>
    DateOnly DataPagamento
);

/// <summary>
/// Corpo da requisição de atualização dos valores de consumo (água e luz).
/// </summary>
public record AtualizarConsumoCorpo(
    /// <summary>Novo valor da conta de água.</summary>
    decimal ValorAgua,
    /// <summary>Novo valor da conta de luz.</summary>
    decimal ValorLuz
);

/// <summary>
/// Corpo da requisição de atualização do código PIX.
/// </summary>
public record AtualizarPixCorpo(
    /// <summary>Novo código ou link do PIX.</summary>
    string CodigoPix
);

/// <summary>
/// Corpo da requisição de geração de cobrança PIX via Asaas.
/// </summary>
public record GerarPixCorpo(
    /// <summary>
    /// Percentual do valor a ser direcionado ao WalletId do host (0-100).
    /// Se nulo, o valor total é direcionado ao host.
    /// </summary>
    decimal? PercentualSplit = null
);

